-- ════════════════════════════════════════════════════════════════
-- Finance-core sandbox blueprints (7 functions)
--
-- Seeds the hands-on technical sandbox (technical_pillars + technical_skill_blocks)
-- for the finance-core functions and flips each to node_status='active'.
-- Mirrors the FP&A reference seed in 00077. Master values are arithmetically
-- validated (scoreBlock=100% on the model answer; SQL executed against a
-- throwaway DB) before generation. Re-runnable: each function's pillars are
-- deleted first (cascades to its blocks).
-- Functions: 1.1, 1.2, 1.3, 1.4, 1.6, 1.8, 1.11
-- ════════════════════════════════════════════════════════════════
-- 1.1 Accounts Payable (AP)
DO $$
DECLARE fn uuid; p1 uuid; p2 uuid; p3 uuid;
BEGIN
  SELECT id INTO fn FROM technical_functions WHERE node_id='1.1';
  IF fn IS NULL THEN RAISE NOTICE 'function 1.1 not found, skipping'; RETURN; END IF;
  DELETE FROM technical_pillars WHERE function_id = fn;  -- re-runnable (cascades to blocks)
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Invoice Control & 3-Way Match','ضبط الفواتير والمطابقة الثلاثية',1) RETURNING id INTO p1;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Vendor Ledger & Month-End AP','دفتر الموردين وإقفال نهاية الشهر',2) RETURNING id INTO p2;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'AP Data Interrogation','استجواب بيانات الحسابات الدائنة',3) RETURNING id INTO p3;
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'Three-Way Match Exception & Payable Determination','تحديد المبلغ المستحق واستثناءات المطابقة الثلاثية','','','IMA Statements on Management Accounting / CIPS P2P Cycle (3-way match)','spreadsheet',1000,'You are the AP controller at Gulf Logistics LLC (Dubai). Supplier Al Madar Trading FZE submitted invoice INV-4471 with five line items. House policy: pay the LOWER of the invoiced quantity and the GRN (received) quantity, always at the PO unit price (any invoice price above the PO price is never paid), and flag a line as a short-delivery exception when the GRN quantity is below the PO quantity by more than the 2% receipt tolerance. All figures in AED. For each line enter the payable value (matched qty x PO unit price) in column B, then compute the total payable to release, the total amount disallowed/held (invoice face value minus total payable), and the count of short-delivery exception lines.','أنت مراقب الحسابات الدائنة في شركة غلف لوجستيكس ش.ذ.م.م (دبي). قدّم المورّد المدار للتجارة الفاتورة INV-4471 المكوّنة من خمسة بنود. سياسة الشركة: السداد على أساس الأقل بين الكمية في الفاتورة والكمية المستلمة في سند الاستلام، دائمًا بسعر أمر الشراء (أي سعر فاتورة يتجاوز سعر أمر الشراء لا يُدفع)، وتُعلّم البند كاستثناء توريد ناقص إذا قلّت الكمية المستلمة عن كمية أمر الشراء بأكثر من حد التسامح 2%. جميع المبالغ بالدرهم الإماراتي. أدخل القيمة المستحقة لكل بند في العمود B (الكمية المطابقة × سعر أمر الشراء)، ثم احسب إجمالي المبلغ المستحق للسداد، وإجمالي المبلغ المرفوض/المحتجز (القيمة الاسمية للفاتورة ناقص إجمالي المستحق)، وعدد بنود استثناء التوريد الناقص.','{"rows":[{"A":"Gulf Logistics LLC - Invoice INV-4471 / Al Madar Trading FZE (AED)","r":1,"kind":"title"},{"A":"Line Payable = MIN(Invoice qty, GRN qty) x PO unit price","r":3,"kind":"section"},{"A":"L1  PO 200 @15.00 | Inv 200 @15.50 | GRN 200  -> payable","r":4,"ref":"B4","hint":"=MIN(200,200)*15.00","editable":true},{"A":"L2  PO 150 @40.00 | Inv 150 @40.00 | GRN 140  -> payable","r":5,"ref":"B5","hint":"=MIN(150,140)*40.00","editable":true},{"A":"L3  PO 500 @8.00  | Inv 520 @8.00  | GRN 500  -> payable","r":6,"ref":"B6","hint":"=MIN(520,500)*8.00","editable":true},{"A":"L4  PO 80  @120.00| Inv 80  @120.00| GRN 80   -> payable","r":7,"ref":"B7","hint":"=MIN(80,80)*120.00","editable":true},{"A":"L5  PO 300 @25.00 | Inv 300 @26.00 | GRN 295  -> payable","r":8,"ref":"B8","hint":"=MIN(300,295)*25.00","editable":true},{"A":"Total Payable to Release","r":10,"ref":"B10","hint":"=SUM(B4:B8)","editable":true},{"A":"Invoice Face Value (Inv qty x Inv price)","B":30660,"r":11,"given":true},{"A":"Total Amount Disallowed / Held","r":12,"ref":"B12","hint":"=B11-B10","editable":true},{"A":"Count of Short-Delivery Exception Lines (GRN < PO by > 2%)","r":13,"ref":"B13","hint":"1","editable":true}],"currency":"AED","editable":["B4","B5","B6","B7","B8","B10","B12","B13"],"sheetName":"ThreeWayMatch"}'::jsonb,'{"cells":{"B4":3000,"B5":5600,"B6":4000,"B7":9600,"B8":7375,"B10":29575,"B12":1085,"B13":1}}'::jsonb,'[{"id":"l1_payable","kind":"cell_value","target":"B4","weight":1,"expected":3000,"label_en":"L1 payable matched correctly (AED 3,000)","label_ar":"البند الأول مطابق بشكل صحيح (3,000 درهم)","tolerance":0.01},{"id":"l3_payable","kind":"cell_value","target":"B6","weight":2,"expected":4000,"label_en":"L3 payable capped at GRN qty x PO price (AED 4,000)","label_ar":"البند الثالث محدود بالكمية المستلمة × سعر أمر الشراء (4,000 درهم)","tolerance":0.01},{"id":"l5_payable","kind":"cell_value","target":"B8","weight":2,"expected":7375,"label_en":"L5 payable uses PO price not invoiced price (AED 7,375)","label_ar":"البند الخامس يستخدم سعر أمر الشراء لا سعر الفاتورة (7,375 درهم)","tolerance":0.01},{"id":"total_payable","kind":"cell_value","target":"B10","weight":3,"expected":29575,"label_en":"Total payable to release (AED 29,575)","label_ar":"إجمالي المبلغ المستحق للسداد (29,575 درهم)","tolerance":0.01},{"id":"disallowed","kind":"cell_value","target":"B12","weight":2,"expected":1085,"label_en":"Total amount disallowed / held (AED 1,085)","label_ar":"إجمالي المبلغ المرفوض/المحتجز (1,085 درهم)","tolerance":0.01},{"id":"exception_count","kind":"cell_value","target":"B13","weight":1,"expected":1,"label_en":"Count of short-delivery exception lines (= 1)","label_ar":"عدد بنود استثناء التوريد الناقص (= 1)","tolerance":0.01}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'VAT Recoverability & Withholding on a Cross-Border Payable','استرداد ضريبة القيمة المضافة والاستقطاع على دفعة عابرة للحدود','','','UAE FTA VAT Federal Decree-Law No. 8 of 2017 (reverse charge & input recovery) / GCC withholding-tax practice','logic_input',540,'Saudi entity Riyadh Petrochem Co. (KSA, VAT-registered, fully taxable) receives a service invoice from a non-resident consultancy with a net professional fee of SAR 400,000. KSA standard VAT is 15% and applies via the reverse-charge mechanism on imported services (the buyer self-accounts output VAT and recovers the same as input VAT in the same return). A 5% withholding tax applies to the non-resident''s service fee and is withheld from the supplier payment and remitted to ZATCA. Compute, in SAR: (1) the reverse-charge output VAT, (2) the recoverable input VAT, (3) the net VAT cash effect of the reverse charge, (4) the withholding tax withheld for ZATCA, and (5) the net cash actually paid to the non-resident supplier.','تتلقى شركة الرياض للبتروكيماويات (السعودية، مسجّلة في ضريبة القيمة المضافة وخاضعة بالكامل) فاتورة خدمات من شركة استشارية غير مقيمة بأتعاب صافية قدرها 400,000 ريال سعودي. ضريبة القيمة المضافة القياسية في السعودية 15% وتُطبّق عبر آلية الاحتساب العكسي على الخدمات المستوردة (يحتسب المشتري ضريبة المخرجات ويستردها كضريبة مدخلات في الإقرار نفسه). تُطبّق ضريبة استقطاع بنسبة 5% على أتعاب المورّد غير المقيم وتُحتجز من دفعته وتُورّد لهيئة الزكاة والضريبة والجمارك. احسب بالريال السعودي: (1) ضريبة المخرجات بالاحتساب العكسي، (2) ضريبة المدخلات القابلة للاسترداد، (3) صافي الأثر النقدي لضريبة القيمة المضافة من الاحتساب العكسي، (4) ضريبة الاستقطاع المحتجزة للهيئة، (5) صافي النقد المدفوع فعليًا للمورّد غير المقيم.','{"fields":[{"id":"output_vat","type":"number","label_en":"Reverse-charge output VAT (SAR)","label_ar":"ضريبة المخرجات بالاحتساب العكسي (ريال)"},{"id":"input_vat","type":"number","label_en":"Recoverable input VAT (SAR)","label_ar":"ضريبة المدخلات القابلة للاسترداد (ريال)"},{"id":"net_vat_effect","type":"number","label_en":"Net VAT cash effect of reverse charge (SAR)","label_ar":"صافي الأثر النقدي لضريبة القيمة المضافة (ريال)"},{"id":"wht_withheld","type":"number","label_en":"Withholding tax withheld for ZATCA (SAR)","label_ar":"ضريبة الاستقطاع المحتجزة للهيئة (ريال)"},{"id":"net_cash_supplier","type":"number","label_en":"Net cash paid to the supplier (SAR)","label_ar":"صافي النقد المدفوع للمورّد (ريال)"}],"scenario":{"note_en":"Reverse charge: buyer self-accounts output VAT and (being fully taxable) recovers the same as input VAT in the same return, so it is cash-neutral. VAT is not paid to a non-resident under reverse charge. WHT is withheld from the fee and remitted to ZATCA, not paid to the supplier.","note_ar":"في الاحتساب العكسي يحتسب المشتري ضريبة المخرجات ويستردها بالكامل كمدخلات في الإقرار نفسه فيكون الأثر النقدي صفرًا. لا تُدفع ضريبة القيمة المضافة للمورّد غير المقيم. تُحتجز ضريبة الاستقطاع من الأتعاب وتُورّد للهيئة ولا تُدفع للمورّد.","net_professional_fee":400000,"vat_rate":0.15,"wht_rate":0.05,"buyer_status":"fully taxable, VAT-registered","currency":"SAR"}}'::jsonb,'{"fields":{"output_vat":60000,"input_vat":60000,"net_vat_effect":0,"wht_withheld":20000,"net_cash_supplier":380000}}'::jsonb,'[{"id":"output_vat","kind":"logic_value","field":"output_vat","weight":1,"expected":60000,"label_en":"Reverse-charge output VAT (SAR 60,000)","label_ar":"ضريبة المخرجات بالاحتساب العكسي (60,000 ريال)","tolerance":0.5},{"id":"input_vat","kind":"logic_value","field":"input_vat","weight":1,"expected":60000,"label_en":"Recoverable input VAT (SAR 60,000)","label_ar":"ضريبة المدخلات القابلة للاسترداد (60,000 ريال)","tolerance":0.5},{"id":"net_vat_effect","kind":"logic_value","field":"net_vat_effect","weight":2,"expected":0,"label_en":"Net VAT cash effect of reverse charge (SAR 0)","label_ar":"صافي الأثر النقدي للاحتساب العكسي (0 ريال)","tolerance":0.5},{"id":"wht_withheld","kind":"logic_value","field":"wht_withheld","weight":2,"expected":20000,"label_en":"Withholding tax withheld for ZATCA (SAR 20,000)","label_ar":"ضريبة الاستقطاع المحتجزة للهيئة (20,000 ريال)","tolerance":0.5},{"id":"net_cash_supplier","kind":"logic_value","field":"net_cash_supplier","weight":3,"expected":380000,"label_en":"Net cash paid to the supplier (SAR 380,000)","label_ar":"صافي النقد المدفوع للمورّد (380,000 ريال)","tolerance":0.5}]'::jsonb,2);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p2,'Early-Payment-Discount Sensitivity Data Table','جدول حساسية خصم السداد المبكر','','','AFP / IMA working-capital management (dynamic discounting; annualized cost of trade credit)','advanced_spreadsheet',900,'Abu Dhabi Industrial Supplies has an open payable to a key vendor with face value AED 500,000 on net 45 terms. The captured discount saving on settling early = invoice x discount%. The base model cell computes invoice x discount% input. Build a NATIVE two-variable data table (do not hardcode the grid) sweeping discount% across the columns (1.0%, 1.5%, 2.0%) and days-paid-early down the rows (10, 20, 30). Wire the column input to the discount% cell and the row input to the days cell. All figures in AED.','لدى أبوظبي للتوريدات الصناعية ذمة دائنة قائمة لمورّد رئيسي بقيمة اسمية 500,000 درهم بشروط صافي 45 يومًا. وفر الخصم المحقّق عند السداد المبكر = الفاتورة × نسبة الخصم. تحسب خلية النموذج الأساسي الفاتورة × مدخل نسبة الخصم. أنشئ جدول بيانات ثنائي المتغير أصليًا (لا تُدخل القيم يدويًا) يمسح نسبة الخصم عبر الأعمدة (1.0%، 1.5%، 2.0%) وعدد أيام السداد المبكر عبر الصفوف (10، 20، 30). اربط مدخل العمود بخلية نسبة الخصم ومدخل الصف بخلية الأيام. جميع المبالغ بالدرهم.','{"rows":[{"A":"Invoice face value","B":500000,"r":1,"given":true},{"A":"Discount % input (column input)","B":0.015,"r":2,"given":true},{"A":"Days paid early input (row input)","B":20,"r":3,"given":true},{"A":"Captured discount saving =Invoice x Discount%","r":5,"ref":"B5","hint":"=B1*B2","editable":true},{"A":"Two-variable Data Table: rows=Days early, cols=Discount%","r":7,"kind":"section"},{"A":"(corner formula links to saving)","r":8,"hint":"=B5","B7ref":"B8","editable":true},{"C":0.01,"D":0.015,"E":0.02,"r":8,"note":"discount% headers C8:E8","given":true},{"A":10,"r":9,"note":"days row header","given":true},{"A":20,"r":10,"given":true},{"A":30,"r":11,"given":true}],"model":{"invoice":"B1","discountPct":"B2","daysEarly":"B3","saving":"B5"},"currency":"AED","editable":["B5","B8","C9:E11"],"dataTable":{"range":"C9:E11","corner":"B8","colInput":"B2","rowInput":"B3"},"sheetName":"DiscountSensitivity"}'::jsonb,'{"cells":{"B5":7500,"C9":5000,"D10":7500,"E11":10000}}'::jsonb,'[{"id":"array_formula","kind":"is_array_formula","target":"C9:E11","weight":3,"label_en":"Grid is a native data table, not hardcoded values","label_ar":"الشبكة جدول بيانات أصلي وليست قيمًا ثابتة"},{"id":"corner_low","kind":"cell_value","target":"C9","weight":1,"expected":5000,"label_en":"Top-left corner: 1.0% discount (AED 5,000)","label_ar":"الزاوية العليا اليسرى: خصم 1.0% (5,000 درهم)","tolerance":0.01},{"id":"center","kind":"cell_value","target":"D10","weight":1,"expected":7500,"label_en":"Centre cell: 1.5% discount (AED 7,500)","label_ar":"الخلية المركزية: خصم 1.5% (7,500 درهم)","tolerance":0.01},{"id":"corner_high","kind":"cell_value","target":"E11","weight":1,"expected":10000,"label_en":"Bottom-right corner: 2.0% discount (AED 10,000)","label_ar":"الزاوية السفلى اليمنى: خصم 2.0% (10,000 درهم)","tolerance":0.01}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p3,'AP Aging Exposure by Supplier (SQL)','التعرض حسب أعمار الديون لكل مورّد (SQL)','','','DAMA DMBOK (data interrogation) / IMA AP aging & liquidity reporting','sql',600,'Query the open AP sub-ledger of Emirates Facilities Management. Table ap_invoices(id, supplier, invoice_amount, due_date, paid) holds open and settled invoices. The reporting date is 2025-03-31. Return total OVERDUE exposure (due_date earlier than the reporting date) for invoices still unpaid (paid = false), grouped by supplier, largest exposure first. Return exactly two columns: supplier, overdue_total.','استعلم عن دفتر الحسابات الدائنة المفتوح لشركة الإمارات لإدارة المرافق. يحتوي الجدول ap_invoices(id, supplier, invoice_amount, due_date, paid) على فواتير مفتوحة ومسدّدة. تاريخ التقرير هو 2025-03-31. أعد إجمالي التعرض المتأخّر (تاريخ الاستحقاق قبل تاريخ التقرير) للفواتير غير المسدّدة (paid = false)، مجمّعًا حسب المورّد، الأكبر أولًا. أعد عمودين فقط: supplier, overdue_total.','{"dialect":"postgres","schema_sql":"CREATE TABLE ap_invoices (id int PRIMARY KEY, supplier text, invoice_amount numeric, due_date date, paid boolean);","seed_sql":"INSERT INTO ap_invoices (id, supplier, invoice_amount, due_date, paid) VALUES (1,''Al Noor Cleaning'',12000,''2025-02-10'',false),(2,''Al Noor Cleaning'',8000,''2025-03-01'',false),(3,''Al Noor Cleaning'',5000,''2025-03-15'',false),(4,''Gulf Security'',20000,''2025-02-20'',false),(5,''Gulf Security'',15000,''2025-03-10'',false),(6,''Oasis Catering'',9000,''2025-03-05'',false),(7,''Oasis Catering'',7000,''2025-04-15'',false),(8,''Oasis Catering'',6000,''2025-02-01'',true),(9,''Desert Maintenance'',4000,''2025-03-20'',false);","prompt_en":"Return total overdue exposure (due_date < reporting date 2025-03-31) for unpaid invoices (paid = false), grouped by supplier, largest first. Columns: supplier, overdue_total.","prompt_ar":"أعد إجمالي التعرض المتأخّر (تاريخ الاستحقاق < تاريخ التقرير 2025-03-31) للفواتير غير المسدّدة (paid = false)، مجمّعًا حسب المورّد، الأكبر أولًا. الأعمدة: supplier, overdue_total."}'::jsonb,'{"master_query":"SELECT supplier, SUM(invoice_amount) AS overdue_total FROM ap_invoices WHERE paid = false AND due_date < DATE ''2025-03-31'' GROUP BY supplier ORDER BY overdue_total DESC, supplier"}'::jsonb,'[{"id":"result_match","kind":"sql_result_match","weight":3,"ordered":true,"label_en":"Result matches master (supplier overdue totals, largest first)","label_ar":"النتيجة تطابق النموذج (إجمالي المتأخّرات لكل مورّد، الأكبر أولًا)"}]'::jsonb,1);
  UPDATE technical_functions SET node_status='active' WHERE id = fn;
END $$;

-- 1.2 Accounts Receivable (AR) & Credit Management
DO $$
DECLARE fn uuid; p1 uuid; p2 uuid; p3 uuid;
BEGIN
  SELECT id INTO fn FROM technical_functions WHERE node_id='1.2';
  IF fn IS NULL THEN RAISE NOTICE 'function 1.2 not found, skipping'; RETURN; END IF;
  DELETE FROM technical_pillars WHERE function_id = fn;  -- re-runnable (cascades to blocks)
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Credit Risk & Provisioning','مخاطر الائتمان والمخصصات',1) RETURNING id INTO p1;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Receivables Performance Analytics','تحليلات أداء الذمم المدينة',2) RETURNING id INTO p2;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Cash Application, Billing & Collections Operations','تطبيق المقبوضات والفوترة وعمليات التحصيل',3) RETURNING id INTO p3;
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'IFRS 9 AR Aging & Expected-Credit-Loss Provision Matrix','مصفوفة أعمار الذمم المدينة ومخصص الخسائر الائتمانية المتوقعة وفق IFRS 9','','','IFRS 9 Financial Instruments (Expected Credit Loss / simplified provision matrix)','spreadsheet',1080,'Gulf Falcon Trading LLC (Dubai) closes its quarter with the AR aging shown (gross balances, AED). Treasury policy applies IFRS 9 simplified-approach lifetime ECL rates by bucket. The opening loss allowance already carried on the balance sheet is AED 95,000. Complete the ECL provision for each bucket (gross x rate), then compute total gross AR, total ECL allowance, net receivable (gross less allowance), and the additional charge that must be posted to the P&L this quarter to bring the allowance up to the required level (required allowance less opening allowance).','تُقفل شركة جلف فالكون للتجارة ذ.م.م (دبي) الربع بأعمار الذمم المدينة الموضحة (أرصدة إجمالية بالدرهم). تطبق سياسة الخزينة معدلات الخسائر الائتمانية المتوقعة على مدى العمر وفق النهج المبسط لـ IFRS 9 لكل فئة. مخصص الخسارة الافتتاحي المُدرج في الميزانية هو 95,000 درهم. احسب مخصص ECL لكل فئة (الإجمالي × المعدل)، ثم إجمالي الذمم المدينة، وإجمالي مخصص ECL، وصافي الذمم المدينة (الإجمالي ناقص المخصص)، والمبلغ الإضافي الواجب تحميله على قائمة الدخل هذا الربع لرفع المخصص إلى المستوى المطلوب (المخصص المطلوب ناقص المخصص الافتتاحي).','{"currency":"AED","sheetName":"ECL Matrix","rows":[{"A":"Gulf Falcon Trading LLC - Quarter-End AR Aging & IFRS 9 ECL (AED)","r":1,"kind":"title"},{"A":"Aging Profile (gross balances, AED)","r":3,"kind":"section"},{"A":"Current - gross","B":1800000,"r":4,"given":true},{"A":"1-30 days past due - gross","B":620000,"r":5,"given":true},{"A":"31-60 days past due - gross","B":340000,"r":6,"given":true},{"A":"61-90 days past due - gross","B":180000,"r":7,"given":true},{"A":"90+ days past due - gross","B":110000,"r":8,"given":true},{"A":"IFRS 9 lifetime ECL rate by bucket","r":10,"kind":"section"},{"A":"Current rate","B":0.005,"r":11,"given":true},{"A":"1-30 days rate","B":0.02,"r":12,"given":true},{"A":"31-60 days rate","B":0.08,"r":13,"given":true},{"A":"61-90 days rate","B":0.2,"r":14,"given":true},{"A":"90+ days rate","B":0.5,"r":15,"given":true},{"A":"ECL Provision by bucket (gross x rate)","r":17,"kind":"section"},{"A":"  Current ECL provision","r":18,"ref":"B18","hint":"=B4*B11","editable":true},{"A":"  1-30 days ECL provision","r":19,"ref":"B19","hint":"=B5*B12","editable":true},{"A":"  31-60 days ECL provision","r":20,"ref":"B20","hint":"=B6*B13","editable":true},{"A":"  61-90 days ECL provision","r":21,"ref":"B21","hint":"=B7*B14","editable":true},{"A":"  90+ days ECL provision","r":22,"ref":"B22","hint":"=B8*B15","editable":true},{"A":"Roll-up","r":24,"kind":"section"},{"A":"Total gross AR","r":25,"ref":"B25","hint":"=SUM(B4:B8)","editable":true},{"A":"Total ECL allowance (required)","r":26,"ref":"B26","hint":"=SUM(B18:B22)","editable":true},{"A":"Net receivable (gross less allowance)","r":27,"ref":"B27","hint":"=B25-B26","editable":true},{"A":"Opening loss allowance carried","B":95000,"r":29,"given":true},{"A":"Additional P&L charge this quarter","r":30,"ref":"B30","hint":"=B26-B29","editable":true}],"editable":["B18","B19","B20","B21","B22","B25","B26","B27","B30"]}'::jsonb,'{"cells":{"B18":9000,"B19":12400,"B20":27200,"B21":36000,"B22":55000,"B25":3050000,"B26":139600,"B27":2910400,"B30":44600}}'::jsonb,'[{"id":"ecl_31_60","kind":"cell_value","target":"B20","weight":1,"expected":27200,"label_en":"31-60 day bucket ECL provision = AED 27,200","label_ar":"مخصص ECL لفئة 31-60 يومًا = 27,200 درهم","tolerance":0.01},{"id":"ecl_90plus","kind":"cell_value","target":"B22","weight":2,"expected":55000,"label_en":"90+ day bucket ECL provision = AED 55,000","label_ar":"مخصص ECL لفئة 90+ يومًا = 55,000 درهم","tolerance":0.01},{"id":"total_gross","kind":"cell_value","target":"B25","weight":1,"expected":3050000,"label_en":"Total gross AR = AED 3,050,000","label_ar":"إجمالي الذمم المدينة = 3,050,000 درهم","tolerance":0.01},{"id":"total_ecl","kind":"cell_value","target":"B26","weight":3,"expected":139600,"label_en":"Total ECL allowance = AED 139,600","label_ar":"إجمالي مخصص ECL = 139,600 درهم","tolerance":0.01},{"id":"net_ar","kind":"cell_value","target":"B27","weight":2,"expected":2910400,"label_en":"Net receivable = AED 2,910,400","label_ar":"صافي الذمم المدينة = 2,910,400 درهم","tolerance":0.01},{"id":"pnl_topup","kind":"cell_value","target":"B30","weight":3,"expected":44600,"label_en":"Additional P&L charge this quarter = AED 44,600","label_ar":"العبء الإضافي على قائمة الدخل هذا الربع = 44,600 درهم","tolerance":0.01}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p2,'Two-Variable DSO Sensitivity Data Table','جدول بيانات حساسية أيام التحصيل بمتغيرين','','','AFP FP&A Body of Knowledge (FPAC) - working-capital / DSO analytics','advanced_spreadsheet',900,'Emaar Facilities Services (Abu Dhabi) wants to stress its Days Sales Outstanding (DSO) under different receivables balances and revenue levels. DSO = (Accounts Receivable / Annual Revenue) x 360. Base case: AR = AED 3,600,000, Annual Revenue = AED 24,000,000. First compute the base-case DSO in B5. Then build a NATIVE two-variable data table in C9:E11 with the AR balance down the rows (3,000,000; 3,600,000; 4,200,000 in A9:A11) and Annual Revenue across the columns (18,000,000; 24,000,000; 30,000,000 in C8:E8). The corner cell B8 must link to the base DSO. Use a genuine data table (row input = AR cell B3, column input = Revenue cell B1) - do not type the DSO values by hand.','ترغب إعمار للخدمات (أبوظبي) في اختبار أيام التحصيل (DSO) تحت أرصدة ذمم وإيرادات مختلفة. DSO = (الذمم المدينة / الإيراد السنوي) × 360. الحالة الأساسية: الذمم = 3,600,000 درهم، الإيراد السنوي = 24,000,000 درهم. احسب أولًا DSO الأساسي في B5. ثم أنشئ جدول بيانات أصليًا بمتغيرين في C9:E11 مع أرصدة الذمم في الصفوف (3,000,000؛ 3,600,000؛ 4,200,000 في A9:A11) والإيراد السنوي في الأعمدة (18,000,000؛ 24,000,000؛ 30,000,000 في C8:E8). يجب أن ترتبط الخلية الزاوية B8 بـ DSO الأساسي. استخدم جدول بيانات حقيقيًا (مُدخل الصف = خلية الذمم B3، مُدخل العمود = خلية الإيراد B1) - لا تُدخل قيم DSO يدويًا.','{"currency":"AED","sheetName":"DSO Sensitivity","rows":[{"A":"Annual Revenue (base)","B":24000000,"r":1,"given":true},{"A":"Day basis","B":360,"r":2,"given":true},{"A":"Accounts Receivable (base)","B":3600000,"r":3,"given":true},{"A":"Base-case DSO =(AR/Revenue)*360","r":5,"ref":"B5","hint":"=(B3/B1)*B2","editable":true},{"A":"Two-variable Data Table: rows=AR, cols=Annual Revenue","r":7,"kind":"section"},{"A":"(corner formula links to base DSO)","r":8,"B7ref":"B8","hint":"=B5","editable":true},{"C":18000000,"D":24000000,"E":30000000,"r":8,"note":"revenue headers C8:E8","given":true},{"A":3000000,"r":9,"note":"AR row header","given":true},{"A":3600000,"r":10,"given":true},{"A":4200000,"r":11,"given":true}],"model":{"ar":"B3","revenue":"B1","dayBasis":"B2","dso":"B5"},"editable":["B5","B8","C9:E11"],"dataTable":{"range":"C9:E11","corner":"B8","colInput":"B1","rowInput":"B3"}}'::jsonb,'{"cells":{"B5":54,"B8":54,"C9":60,"D10":54,"E11":50.4}}'::jsonb,'[{"id":"array_formula","kind":"is_array_formula","target":"C9:E11","weight":3,"label_en":"Sensitivity grid uses a native two-variable data table {=TABLE()} (not hardcoded)","label_ar":"شبكة الحساسية تستخدم جدول بيانات أصليًا بمتغيرين {=TABLE()} وليس قيمًا ثابتة"},{"id":"corner_low","kind":"cell_value","target":"C9","weight":1,"expected":60,"label_en":"Low corner DSO (AR 3,000,000, Rev 18,000,000) = 60.0 days","label_ar":"DSO الزاوية الدنيا (ذمم 3,000,000، إيراد 18,000,000) = 60.0 يومًا","tolerance":0.01},{"id":"center_base","kind":"cell_value","target":"D10","weight":2,"expected":54,"label_en":"Base-case DSO (AR 3,600,000, Rev 24,000,000) = 54.0 days","label_ar":"DSO الحالة الأساسية (ذمم 3,600,000، إيراد 24,000,000) = 54.0 يومًا","tolerance":0.01},{"id":"corner_high","kind":"cell_value","target":"E11","weight":1,"expected":50.4,"label_en":"High corner DSO (AR 4,200,000, Rev 30,000,000) = 50.4 days","label_ar":"DSO الزاوية العليا (ذمم 4,200,000، إيراد 30,000,000) = 50.4 يومًا","tolerance":0.01}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p3,'Cash Application with Early-Pay Discount & Credit-Limit Reconciliation','تطبيق المقبوضات مع خصم السداد المبكر وتسوية حد الائتمان','','','IMA / CIMA Management Accounting - receivables operations, trade-discount terms (2/10 net 30)','logic_input',600,'Customer Al Faisal Trading has an approved credit limit of AED 500,000 and three open invoices: INV-1001 = AED 240,000, INV-1002 = AED 96,000, INV-1003 = AED 60,000 (open AR before this receipt = AED 396,000). All invoices carry 2/10 net 30 terms. Al Faisal remits AED 329,280 within the discount period; the remittance advice instructs you to fully settle INV-1001 and INV-1002 and to take the 2% early-payment discount on both. INV-1003 is left open. Al Faisal then asks to place a new order worth AED 470,000. Compute: (1) the early-payment discount allowed on this application; (2) the remaining AR balance after applying the cash; (3) the available credit after application; and (4) the amount by which the new order would exceed available credit (the over-limit excess needing approval).','العميل الفيصل للتجارة لديه حد ائتمان معتمد قدره 500,000 درهم وثلاث فواتير مفتوحة: INV-1001 = 240,000 درهم، INV-1002 = 96,000 درهم، INV-1003 = 60,000 درهم (الذمم المفتوحة قبل هذا المقبوض = 396,000 درهم). جميع الفواتير بشروط 2/10 صافي 30. يحوّل الفيصل 329,280 درهمًا خلال فترة الخصم، مع إشعار تحويل يوجّه بتسوية INV-1001 و INV-1002 بالكامل وأخذ خصم السداد المبكر 2% على كليهما. تبقى INV-1003 مفتوحة. ثم يطلب الفيصل تقديم طلب جديد بقيمة 470,000 درهم. احسب: (1) خصم السداد المبكر المسموح به على هذا التطبيق؛ (2) رصيد الذمم المتبقي بعد تطبيق النقد؛ (3) الائتمان المتاح بعد التطبيق؛ (4) المبلغ الذي يتجاوز به الطلب الجديد الائتمان المتاح (الفائض عن الحد الذي يستلزم الموافقة).','{"fields":[{"id":"discount_allowed","type":"number","label_en":"Early-payment discount allowed (AED)","label_ar":"خصم السداد المبكر المسموح به (درهم)"},{"id":"remaining_ar","type":"number","label_en":"Remaining AR after application (AED)","label_ar":"الذمم المتبقية بعد التطبيق (درهم)"},{"id":"available_credit","type":"number","label_en":"Available credit after application (AED)","label_ar":"الائتمان المتاح بعد التطبيق (درهم)"},{"id":"over_limit_excess","type":"number","label_en":"New-order over-limit excess (AED)","label_ar":"فائض الطلب الجديد عن الحد (درهم)"}],"scenario":{"note_en":"Apply the remittance against the instructed invoices net of the 2% early-pay discount, roll forward AR and available credit, then test the new order against the limit. Discount is computed on the settled invoice face value, not on the cash received or the full open AR.","note_ar":"طبّق المقبوض على الفواتير الموجّهة بعد خصم السداد المبكر 2%، ثم رحّل الذمم والائتمان المتاح، ثم اختبر الطلب الجديد مقابل الحد. يُحسب الخصم على القيمة الاسمية للفواتير المسددة، وليس على النقد المستلم أو إجمالي الذمم المفتوحة.","credit_limit":500000,"open_ar_before":396000,"discount_terms":"2/10 net 30","discount_rate":0.02,"cash_received":329280,"new_order":470000,"invoices":[{"invoice_no":"INV-1001","amount":240000,"instruction":"settle in full, take discount"},{"invoice_no":"INV-1002","amount":96000,"instruction":"settle in full, take discount"},{"invoice_no":"INV-1003","amount":60000,"instruction":"leave open"}]}}'::jsonb,'{"fields":{"discount_allowed":6720,"remaining_ar":60000,"available_credit":440000,"over_limit_excess":30000}}'::jsonb,'[{"id":"discount","kind":"logic_value","field":"discount_allowed","weight":2,"expected":6720,"label_en":"Early-payment discount allowed = AED 6,720","label_ar":"خصم السداد المبكر المسموح به = 6,720 درهم","tolerance":0.5},{"id":"remaining","kind":"logic_value","field":"remaining_ar","weight":2,"expected":60000,"label_en":"Remaining AR after application = AED 60,000","label_ar":"الذمم المتبقية بعد التطبيق = 60,000 درهم","tolerance":0.5},{"id":"available","kind":"logic_value","field":"available_credit","weight":2,"expected":440000,"label_en":"Available credit after application = AED 440,000","label_ar":"الائتمان المتاح بعد التطبيق = 440,000 درهم","tolerance":0.5},{"id":"over_limit","kind":"logic_value","field":"over_limit_excess","weight":3,"expected":30000,"label_en":"New-order over-limit excess = AED 30,000","label_ar":"فائض الطلب الجديد عن الحد = 30,000 درهم","tolerance":0.5}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p3,'Overdue AR Ledger Interrogation (Collections Worklist)','استجواب دفتر الذمم المدينة المتأخرة (قائمة عمل التحصيل)','','','DAMA International (DMBOK) - relational data interrogation for receivables analytics','sql',600,'You manage collections for Dana Gas Distribution. The ar_invoices table holds one row per invoice (id, customer, invoice_no, amount, due_date, status). As of the reporting date 2025-03-31, build the collections worklist: return the total OUTSTANDING OVERDUE balance per customer - counting only invoices whose status is ''open'' AND whose due_date is before 2025-03-31 - with the largest overdue balance first. Columns: customer, total_overdue.','أنت تدير التحصيل لدى دانة غاز للتوزيع. يحتوي جدول ar_invoices على صف لكل فاتورة (id, customer, invoice_no, amount, due_date, status). اعتبارًا من تاريخ التقرير 2025-03-31، أنشئ قائمة عمل التحصيل: أعِد إجمالي الرصيد القائم المتأخر لكل عميل - مع احتساب الفواتير التي حالتها ''open'' وتاريخ استحقاقها قبل 2025-03-31 فقط - مرتبًا الأكبر رصيدًا متأخرًا أولًا. الأعمدة: customer, total_overdue.','{"dialect":"postgres","schema_sql":"CREATE TABLE ar_invoices (id int PRIMARY KEY, customer text, invoice_no text, amount numeric, due_date date, status text);","seed_sql":"INSERT INTO ar_invoices (id, customer, invoice_no, amount, due_date, status) VALUES (1,''Nakheel'',''INV-1001'',200000,''2025-02-15'',''open''),(2,''Nakheel'',''INV-1002'',30000,''2025-03-10'',''open''),(3,''Gulf Cement'',''INV-2001'',150000,''2025-02-28'',''open''),(4,''Gulf Cement'',''INV-2002'',90000,''2025-04-10'',''open''),(5,''Al Faisal'',''INV-3001'',60000,''2025-03-01'',''open''),(6,''Al Faisal'',''INV-3002'',80000,''2025-03-20'',''open''),(7,''Emirates Steel'',''INV-4001'',40000,''2025-02-05'',''open''),(8,''Emirates Steel'',''INV-4002'',55000,''2025-03-12'',''paid''),(9,''Nakheel'',''INV-1003'',45000,''2025-03-31'',''open'');","prompt_en":"As of 2025-03-31, return the total outstanding overdue balance per customer (status = ''open'' AND due_date < ''2025-03-31''), largest first. Columns: customer, total_overdue.","prompt_ar":"اعتبارًا من 2025-03-31، أعِد إجمالي الرصيد القائم المتأخر لكل عميل (status = ''open'' و due_date < ''2025-03-31'')، الأكبر أولًا. الأعمدة: customer, total_overdue."}'::jsonb,'{"master_query":"SELECT customer, SUM(amount) AS total_overdue FROM ar_invoices WHERE status = ''open'' AND due_date < ''2025-03-31'' GROUP BY customer ORDER BY total_overdue DESC, customer"}'::jsonb,'[{"id":"result_match","kind":"sql_result_match","weight":3,"ordered":true,"label_en":"Result matches master overdue-by-customer worklist in descending order","label_ar":"النتيجة تطابق قائمة العمل النموذجية للذمم المتأخرة حسب العميل بترتيب تنازلي"}]'::jsonb,2);
  UPDATE technical_functions SET node_status='active' WHERE id = fn;
END $$;

-- 1.3 Core General Ledger (GL) Accounting
DO $$
DECLARE fn uuid; p1 uuid; p2 uuid; p3 uuid;
BEGIN
  SELECT id INTO fn FROM technical_functions WHERE node_id='1.3';
  IF fn IS NULL THEN RAISE NOTICE 'function 1.3 not found, skipping'; RETURN; END IF;
  DELETE FROM technical_pillars WHERE function_id = fn;  -- re-runnable (cascades to blocks)
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Double-Entry & Period-End Mechanics','آليات القيد المزدوج وإقفال نهاية الفترة',1) RETURNING id INTO p1;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Reconciliation & Intercompany Control','التسوية والرقابة على المعاملات بين الشركات',2) RETURNING id INTO p2;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Ledger Interrogation & Chart-of-Accounts Control','استجواب دفتر الأستاذ والرقابة على شجرة الحسابات',3) RETURNING id INTO p3;
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'Adjusted Trial Balance Assembly & Double-Entry Posting','تجميع ميزان المراجعة المعدّل وترحيل القيد المزدوج','','','IAS 1 Presentation of Financial Statements / IFRS Fundamentals (double-entry; IAS 16 depreciation)','spreadsheet',1100,'Emirates Falcon Trading LLC (Dubai) is closing March 2025. The unadjusted trial balance is given in AED (and ties out: total Dr = total Cr = 1,830,000). Post the three period-end adjustments into the editable cells, then extend each affected account to its adjusted balance and prove the ledger ties out. Adjustments: (1) Prepaid insurance is a 12-month policy bought 1 Jan 2025 for AED 36,000 - expense the months elapsed to 31 Mar (3 months). (2) Equipment (cost AED 600,000) is depreciated straight-line over 10 years, nil residual - book ONE month of depreciation (IAS 16). (3) Accrue unbilled salaries of AED 20,000 (given). Complete the adjustment amounts, the adjusted balances, the two adjusted totals, and the balance check (which must equal 0).','تقوم شركة إميرتس فالكون للتجارة ذ.م.م (دبي) بإقفال شهر مارس 2025. ميزان المراجعة غير المعدّل معطى بالدرهم (وهو متوازن: إجمالي المدين = إجمالي الدائن = 1,830,000). رحّل التسويات الثلاث لنهاية الفترة في الخلايا القابلة للتعديل، ثم مدّد كل حساب متأثر إلى رصيده المعدّل وأثبت توازن الدفتر. التسويات: (1) التأمين المدفوع مقدماً هو وثيقة 12 شهراً اشتُريت في 1 يناير 2025 بمبلغ 36,000 درهم - حمّل الأشهر المنقضية حتى 31 مارس (3 أشهر). (2) المعدات (تكلفة 600,000 درهم) تُهلك بالقسط الثابت على 10 سنوات بقيمة متبقية صفر - سجّل إهلاك شهر واحد (المعيار المحاسبي الدولي 16). (3) استحقاق رواتب غير مفوترة بمبلغ 20,000 درهم (معطى). أكمل مبالغ التسوية والأرصدة المعدّلة والإجماليين المعدّلين وفحص التوازن (الذي يجب أن يساوي 0).','{"rows":[{"A":"Emirates Falcon Trading LLC - March 2025 Close (AED)","r":1,"kind":"title"},{"A":"Unadjusted Trial Balance - Debit accounts","r":3,"kind":"section"},{"A":"Cash","B":420000,"r":4,"given":true},{"A":"Accounts Receivable","B":310000,"r":5,"given":true},{"A":"Prepaid Insurance (unadjusted)","B":36000,"r":6,"given":true},{"A":"Equipment (cost)","B":600000,"r":7,"given":true},{"A":"Salaries Expense (unadjusted)","B":240000,"r":8,"given":true},{"A":"Insurance Expense (unadjusted)","B":0,"r":9,"given":true},{"A":"Depreciation Expense (unadjusted)","B":0,"r":10,"given":true},{"A":"Rent Expense","B":199000,"r":11,"given":true},{"A":"Unadjusted Trial Balance - Credit accounts","r":13,"kind":"section"},{"A":"Accumulated Depreciation","B":150000,"r":14,"given":true},{"A":"Accounts Payable","B":185000,"r":15,"given":true},{"A":"Share Capital","B":700000,"r":16,"given":true},{"A":"Retained Earnings","B":120000,"r":17,"given":true},{"A":"Revenue","B":650000,"r":18,"given":true},{"A":"Adjusting entries - post the amounts","r":20,"kind":"section"},{"A":"  Adj 1: Insurance expense for elapsed months (36,000/12 x 3)","r":21,"ref":"B21","hint":"=B6/12*3","editable":true},{"A":"  Adj 2: One month depreciation (600,000/10/12)","r":22,"ref":"B22","hint":"=B7/10/12","editable":true},{"A":"  Adj 3: Accrued unbilled salaries (given)","B":20000,"r":23,"given":true},{"A":"Adjusted balances","r":25,"kind":"section"},{"A":"  Adjusted Prepaid Insurance","r":26,"ref":"B26","hint":"=B6-B21","editable":true},{"A":"  Adjusted Insurance Expense","r":27,"ref":"B27","hint":"=B9+B21","editable":true},{"A":"  Adjusted Depreciation Expense","r":28,"ref":"B28","hint":"=B10+B22","editable":true},{"A":"  Adjusted Accumulated Depreciation","r":29,"ref":"B29","hint":"=B14+B22","editable":true},{"A":"  Adjusted Salaries Expense","r":30,"ref":"B30","hint":"=B8+B23","editable":true},{"A":"  Accrued Salaries Payable (new credit)","r":31,"ref":"B31","hint":"=B23","editable":true},{"A":"Adjusted trial balance totals","r":33,"kind":"section"},{"A":"  Total Adjusted Debits","r":34,"ref":"B34","hint":"=B4+B5+B26+B7+B30+B27+B28+B11","editable":true},{"A":"  Total Adjusted Credits","r":35,"ref":"B35","hint":"=B29+B15+B31+B16+B17+B18","editable":true},{"A":"  Balance Check (Total Dr - Total Cr)","r":37,"ref":"B37","hint":"=B34-B35","editable":true}],"currency":"AED","editable":["B21","B22","B26","B27","B28","B29","B30","B31","B34","B35","B37"],"sheetName":"AdjustedTB"}'::jsonb,'{"cells":{"B21":9000,"B22":5000,"B26":27000,"B27":9000,"B28":5000,"B29":155000,"B30":260000,"B31":20000,"B34":1830000,"B35":1830000,"B37":0}}'::jsonb,'[{"id":"adj_prepaid","kind":"cell_value","target":"B26","weight":2,"expected":27000,"label_en":"Adjusted Prepaid Insurance = 27,000 (36,000 less 3 months at 3,000)","label_ar":"التأمين المدفوع مقدماً المعدّل = 27,000 (36,000 ناقص 3 أشهر بـ 3,000)","tolerance":0.01},{"id":"adj_ins_exp","kind":"cell_value","target":"B27","weight":1,"expected":9000,"label_en":"Adjusted Insurance Expense = 9,000","label_ar":"مصروف التأمين المعدّل = 9,000","tolerance":0.01},{"id":"month_dep","kind":"cell_value","target":"B22","weight":2,"expected":5000,"label_en":"Monthly Depreciation Expense = 5,000 (600,000/10yr/12mo, IAS 16)","label_ar":"مصروف الإهلاك الشهري = 5,000 (600,000/10 سنوات/12 شهراً، المعيار 16)","tolerance":0.01},{"id":"adj_accum_dep","kind":"cell_value","target":"B29","weight":1,"expected":155000,"label_en":"Adjusted Accumulated Depreciation = 155,000","label_ar":"مجمع الإهلاك المعدّل = 155,000","tolerance":0.01},{"id":"adj_salaries","kind":"cell_value","target":"B30","weight":1,"expected":260000,"label_en":"Adjusted Salaries Expense = 260,000 (240,000 + 20,000 accrual)","label_ar":"مصروف الرواتب المعدّل = 260,000 (240,000 + استحقاق 20,000)","tolerance":0.01},{"id":"balance_check","kind":"cell_value","target":"B37","weight":3,"expected":0,"label_en":"Balance check (Total adjusted Dr - Total adjusted Cr) = 0","label_ar":"فحص التوازن (إجمالي المدين المعدّل - إجمالي الدائن المعدّل) = 0","tolerance":0.01}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'Accruals, Prepayments & Provisions Period Apportionment','توزيع الاستحقاقات والمصروفات المدفوعة مقدماً والمخصصات على الفترة','','','IAS 37 Provisions, Contingent Liabilities & Assets / IFRS accruals concept (IAS 1)','logic_input',540,'You are preparing the 31 December 2025 year-end cut-off entries for Najd Industrial Co. (Riyadh), reporting in SAR. Quantify each of four period-end items: (1) Prepaid maintenance balance to carry forward; (2) Accrued (unreceived) electricity expense; (3) End-of-service / GOSI-related leave provision balance; (4) Accrued loan interest at year-end. Enter each amount in SAR.','تقوم بإعداد قيود الفصل في نهاية السنة بتاريخ 31 ديسمبر 2025 لشركة نجد الصناعية (الرياض)، بالريال السعودي. حدّد قيمة كل بند من البنود الأربعة لنهاية الفترة: (1) رصيد الصيانة المدفوعة مقدماً المُرحّل؛ (2) مصروف الكهرباء المستحق (غير المستلمة فاتورته)؛ (3) رصيد مخصص الإجازات/نهاية الخدمة المتعلق بالتأمينات الاجتماعية؛ (4) فائدة القرض المستحقة في نهاية السنة. أدخل كل مبلغ بالريال السعودي.','{"fields":[{"id":"prepaid_maintenance","type":"number","label_en":"Prepaid maintenance carried forward (SAR)","label_ar":"الصيانة المدفوعة مقدماً المُرحّلة (ريال)"},{"id":"accrued_electricity","type":"number","label_en":"Accrued electricity expense (SAR)","label_ar":"مصروف الكهرباء المستحق (ريال)"},{"id":"leave_provision","type":"number","label_en":"Leave / end-of-service provision (SAR)","label_ar":"مخصص الإجازات / نهاية الخدمة (ريال)"},{"id":"accrued_interest","type":"number","label_en":"Accrued loan interest (SAR)","label_ar":"فائدة القرض المستحقة (ريال)"}],"scenario":{"note_en":"Quantify the four 31 Dec 2025 cut-off items for Najd Industrial Co. (Riyadh), SAR. Watch the prepaid trap: carry forward REMAINING months, not elapsed.","note_ar":"حدّد قيمة بنود الفصل الأربعة بتاريخ 31 ديسمبر 2025 لشركة نجد الصناعية (الرياض)، بالريال. انتبه لفخ المدفوع مقدماً: رحّل الأشهر المتبقية وليس المنقضية.","items":[{"ref":1,"desc_en":"Annual maintenance contract SAR 144,000 paid in advance on 1 Sep 2025 covering 12 months. Compute the PREPAID (asset) balance to carry forward at 31 Dec 2025.","desc_ar":"عقد صيانة سنوي بمبلغ 144,000 ريال مدفوع مقدماً في 1 سبتمبر 2025 يغطي 12 شهراً. احسب رصيد المدفوع مقدماً (الأصل) المُرحّل في 31 ديسمبر 2025.","annual_amount":144000,"paid_date":"2025-09-01","months_covered":12},{"ref":2,"desc_en":"December electricity invoice of SAR 28,000 not yet received. Compute the ACCRUED EXPENSE to recognise.","desc_ar":"فاتورة كهرباء ديسمبر بمبلغ 28,000 ريال لم تُستلم بعد. احسب المصروف المستحق الواجب الاعتراف به.","invoice_amount":28000},{"ref":3,"desc_en":"End-of-service / GOSI-related leave provision accrues at SAR 2,400 per completed month; the employee completed 9 months in 2025. Compute the PROVISION balance.","desc_ar":"مخصص الإجازات/نهاية الخدمة المتعلق بالتأمينات يتراكم بمعدل 2,400 ريال لكل شهر مكتمل؛ أكمل الموظف 9 أشهر في 2025. احسب رصيد المخصص.","per_month":2400,"months_completed":9},{"ref":4,"desc_en":"Interest on a SAR 500,000 loan at 6% per annum, paid annually in arrears; the loan was drawn on 1 Oct 2025. Compute the ACCRUED INTEREST at 31 Dec 2025.","desc_ar":"فائدة على قرض بمبلغ 500,000 ريال بمعدل 6% سنوياً، تُدفع سنوياً في المتأخر؛ سُحب القرض في 1 أكتوبر 2025. احسب الفائدة المستحقة في 31 ديسمبر 2025.","principal":500000,"annual_rate":0.06,"drawn_date":"2025-10-01"}]}}'::jsonb,'{"fields":{"prepaid_maintenance":96000,"accrued_electricity":28000,"leave_provision":21600,"accrued_interest":7500}}'::jsonb,'[{"id":"prepaid","kind":"logic_value","field":"prepaid_maintenance","weight":3,"expected":96000,"label_en":"Prepaid maintenance carried forward = 96,000 (8 remaining months at 12,000)","label_ar":"الصيانة المدفوعة مقدماً المُرحّلة = 96,000 (8 أشهر متبقية بـ 12,000)","tolerance":0.5},{"id":"electricity","kind":"logic_value","field":"accrued_electricity","weight":1,"expected":28000,"label_en":"Accrued electricity expense = 28,000","label_ar":"مصروف الكهرباء المستحق = 28,000","tolerance":0.5},{"id":"provision","kind":"logic_value","field":"leave_provision","weight":2,"expected":21600,"label_en":"Leave / end-of-service provision = 21,600 (9 months at 2,400)","label_ar":"مخصص الإجازات / نهاية الخدمة = 21,600 (9 أشهر بـ 2,400)","tolerance":0.5},{"id":"interest","kind":"logic_value","field":"accrued_interest","weight":2,"expected":7500,"label_en":"Accrued loan interest = 7,500 (500,000 x 6% x 3/12)","label_ar":"فائدة القرض المستحقة = 7,500 (500,000 × 6% × 3/12)","tolerance":0.5}]'::jsonb,2);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p2,'Bank Reconciliation & Intercompany Elimination to Zero','التسوية البنكية واستبعاد المعاملات بين الشركات حتى الصفر','','','IAS 1 / IFRS 10 Consolidated Financial Statements (intercompany elimination) + month-end close controls','logic_input',720,'Two related closing controls for Gulf Cement Holding (Abu Dhabi), in AED. PART A - Bank reconciliation at 31 May 2025: the GL Cash book shows AED 318,400; the bank statement shows AED 351,900. Reconciling items: outstanding (unpresented) cheques AED 47,200; deposits in transit AED 22,500; an unrecorded electronic customer receipt AED 12,500; a bank charge AED 1,300 not yet in the books; a customer cheque returned NSF AED 2,400 that the books still treat as banked. Compute (i) the ADJUSTED BANK balance (statement +/- timing items) and (ii) the ADJUSTED BOOK balance (book +/- items not yet recorded); they must AGREE. PART B - Intercompany elimination: the Parent''s books show an intercompany RECEIVABLE from Subsidiary of AED 130,000; the Subsidiary''s books show an intercompany PAYABLE to Parent of AED 118,000; the AED 12,000 difference is goods-in-transit invoiced by Parent but not yet received by Subsidiary. After the Subsidiary books the in-transit goods, compute (iii) the Subsidiary intercompany payable and (iv) the NET intercompany balance on consolidation (must be 0).','ضابطان للإقفال لشركة الخليج للأسمنت القابضة (أبوظبي)، بالدرهم. الجزء أ - التسوية البنكية في 31 مايو 2025: يُظهر دفتر النقدية في الأستاذ 318,400 درهم؛ ويُظهر كشف البنك 351,900 درهم. بنود التسوية: شيكات معلقة (غير مقدمة) 47,200 درهم؛ إيداعات في الطريق 22,500 درهم؛ مقبوض إلكتروني من عميل غير مسجّل 12,500 درهم؛ رسوم بنكية 1,300 درهم لم تُسجّل بعد في الدفاتر؛ شيك عميل مرتجع لعدم كفاية الرصيد 2,400 درهم ما زالت الدفاتر تعتبره مودعاً. احسب (1) رصيد البنك المعدّل (الكشف +/- بنود التوقيت) و(2) رصيد الدفاتر المعدّل (الدفتر +/- البنود غير المسجلة)؛ يجب أن يتطابقا. الجزء ب - الاستبعاد بين الشركات: تُظهر دفاتر الشركة الأم ذمة مدينة من الشركة التابعة بمبلغ 130,000 درهم؛ وتُظهر دفاتر التابعة ذمة دائنة للأم بمبلغ 118,000 درهم؛ الفرق 12,000 درهم هو بضاعة في الطريق فوترتها الأم ولم تستلمها التابعة. بعد أن تسجّل التابعة البضاعة في الطريق، احسب (3) الذمة الدائنة للتابعة و(4) صافي رصيد المعاملات بين الشركات عند التوحيد (يجب أن يكون 0).','{"fields":[{"id":"adjusted_bank","type":"number","label_en":"Adjusted bank balance (AED)","label_ar":"رصيد البنك المعدّل (درهم)"},{"id":"adjusted_book","type":"number","label_en":"Adjusted book balance (AED)","label_ar":"رصيد الدفاتر المعدّل (درهم)"},{"id":"sub_payable","type":"number","label_en":"Subsidiary intercompany payable after booking goods-in-transit (AED)","label_ar":"الذمة الدائنة للتابعة بعد تسجيل البضاعة في الطريق (درهم)"},{"id":"net_intercompany","type":"number","label_en":"Net intercompany balance on consolidation (AED)","label_ar":"صافي رصيد المعاملات بين الشركات عند التوحيد (درهم)"}],"scenario":{"note_en":"Gulf Cement Holding (Abu Dhabi), AED. PART A bank rec must tie adjusted bank to adjusted book; PART B intercompany must net to 0 after aligning the reciprocal balances.","note_ar":"شركة الخليج للأسمنت القابضة (أبوظبي)، بالدرهم. الجزء أ: يجب أن تربط التسوية البنكية رصيد البنك المعدّل برصيد الدفاتر المعدّل؛ الجزء ب: يجب أن يكون صافي المعاملات بين الشركات 0 بعد مواءمة الأرصدة المتبادلة.","part_a":{"book_balance":318400,"bank_statement_balance":351900,"outstanding_cheques":47200,"deposits_in_transit":22500,"unrecorded_electronic_receipt":12500,"unrecorded_bank_charge":1300,"nsf_returned_cheque":2400},"part_b":{"parent_intercompany_receivable":130000,"subsidiary_intercompany_payable":118000,"goods_in_transit":12000}}}'::jsonb,'{"fields":{"adjusted_bank":327200,"adjusted_book":327200,"sub_payable":130000,"net_intercompany":0}}'::jsonb,'[{"id":"adj_bank","kind":"logic_value","field":"adjusted_bank","weight":2,"expected":327200,"label_en":"Adjusted bank balance = 327,200 (statement less outstanding cheques plus deposits in transit)","label_ar":"رصيد البنك المعدّل = 327,200 (الكشف ناقص الشيكات المعلقة زائد الإيداعات في الطريق)","tolerance":0.5},{"id":"adj_book","kind":"logic_value","field":"adjusted_book","weight":3,"expected":327200,"label_en":"Adjusted book balance agrees at 327,200","label_ar":"رصيد الدفاتر المعدّل يتطابق عند 327,200","tolerance":0.5},{"id":"sub_payable_cp","kind":"logic_value","field":"sub_payable","weight":2,"expected":130000,"label_en":"Subsidiary intercompany payable after booking goods-in-transit = 130,000","label_ar":"الذمة الدائنة للتابعة بعد تسجيل البضاعة في الطريق = 130,000","tolerance":0.5},{"id":"net_ic","kind":"logic_value","field":"net_intercompany","weight":3,"expected":0,"label_en":"Net intercompany balance on consolidation = 0","label_ar":"صافي رصيد المعاملات بين الشركات عند التوحيد = 0","tolerance":0.5}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p3,'GL Account Aggregation & Out-of-Balance Detection (SQL)','تجميع حسابات الأستاذ واكتشاف عدم التوازن (SQL)','','','DAMA DMBOK (data interrogation) / chart-of-accounts control + double-entry integrity','sql',660,'You have a seeded general_ledger table for Al-Manar Logistics (Jeddah), in SAR, with one row per posting line. For each account_type, return the net movement = SUM(debit) - SUM(credit) for postings in Q1 2025 ONLY (1 Jan to 31 Mar 2025), grouped by account_type, ordered by net_movement descending (tie-break account_type ascending). Columns: account_type, net_movement. In a valid double-entry ledger the net_movement across all returned rows sums to zero. Postings dated outside Q1 2025 must be excluded.','لديك جدول general_ledger مُعبّأ لشركة المنار للخدمات اللوجستية (جدة)، بالريال السعودي، بصف واحد لكل سطر ترحيل. لكل account_type، أرجِع صافي الحركة = SUM(debit) - SUM(credit) للترحيلات في الربع الأول من 2025 فقط (1 يناير إلى 31 مارس 2025)، مجمّعة حسب account_type، ومرتبة تنازلياً حسب net_movement (وعند التعادل تصاعدياً حسب account_type). الأعمدة: account_type, net_movement. في دفتر قيد مزدوج صحيح يكون مجموع net_movement عبر كل الصفوف صفراً. يجب استبعاد الترحيلات خارج الربع الأول من 2025.','{"dialect":"postgres","schema_sql":"CREATE TABLE general_ledger (entry_id int PRIMARY KEY, account_code text, account_name text, account_type text, debit numeric, credit numeric, posting_date date);","seed_sql":"INSERT INTO general_ledger (entry_id, account_code, account_name, account_type, debit, credit, posting_date) VALUES (1,''1010'',''Cash'',''asset'',350000,0,''2025-01-15''),(2,''1100'',''Accounts Receivable'',''asset'',150000,0,''2025-02-10''),(3,''1010'',''Cash'',''asset'',0,200000,''2025-03-05''),(4,''6000'',''Salaries Expense'',''expense'',180000,0,''2025-01-31''),(5,''6100'',''Rent Expense'',''expense'',70000,0,''2025-02-28''),(6,''2000'',''Accounts Payable'',''liability'',50000,0,''2025-03-20''),(7,''2500'',''Bank Loan'',''liability'',0,200000,''2025-01-20''),(8,''3000'',''Share Capital'',''equity'',0,100000,''2025-01-02''),(9,''4000'',''Sales Revenue'',''revenue'',0,300000,''2025-02-15''),(10,''1010'',''Cash'',''asset'',80000,0,''2025-04-08''),(11,''4000'',''Sales Revenue'',''revenue'',0,80000,''2025-04-08'');","prompt_en":"Return account_type and net_movement = SUM(debit) - SUM(credit) for Q1 2025 postings only, grouped by account_type, ordered by net_movement descending then account_type ascending.","prompt_ar":"أرجِع account_type وnet_movement = SUM(debit) - SUM(credit) لترحيلات الربع الأول من 2025 فقط، مجمّعة حسب account_type، مرتبة تنازلياً حسب net_movement ثم تصاعدياً حسب account_type."}'::jsonb,'{"master_query":"SELECT account_type, SUM(debit) - SUM(credit) AS net_movement FROM general_ledger WHERE posting_date BETWEEN ''2025-01-01'' AND ''2025-03-31'' GROUP BY account_type ORDER BY net_movement DESC, account_type"}'::jsonb,'[{"id":"result_match","kind":"sql_result_match","weight":3,"ordered":true,"label_en":"Result matches master: account_type with net_movement (SUM debit - SUM credit), Q1 2025 only, ordered net_movement descending","label_ar":"النتيجة تطابق النموذج: account_type مع net_movement (SUM المدين - SUM الدائن)، الربع الأول 2025 فقط، مرتبة تنازلياً حسب net_movement"}]'::jsonb,1);
  UPDATE technical_functions SET node_status='active' WHERE id = fn;
END $$;

-- 1.4 Fixed Assets & Capital Accounting
DO $$
DECLARE fn uuid; p1 uuid; p2 uuid; p3 uuid;
BEGIN
  SELECT id INTO fn FROM technical_functions WHERE node_id='1.4';
  IF fn IS NULL THEN RAISE NOTICE 'function 1.4 not found, skipping'; RETURN; END IF;
  DELETE FROM technical_pillars WHERE function_id = fn;  -- re-runnable (cascades to blocks)
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Capitalization & Depreciation Mechanics','آليات الرسملة والإهلاك',1) RETURNING id INTO p1;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Impairment & Recoverable Amount','اضمحلال القيمة والمبلغ القابل للاسترداد',2) RETURNING id INTO p2;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Asset Register Interrogation','استجواب سجل الأصول',3) RETURNING id INTO p3;
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'IAS 16 Componentized Capitalization & Depreciation Roll-Forward','الرسملة المجزأة وفق المعيار المحاسبي الدولي 16 وجدول ترحيل الإهلاك','','','IAS 16 Property, Plant & Equipment / IMA CMA','spreadsheet',1100,'Emirates Capital Holdings (Dubai) is capitalizing a new corporate HQ fit-out under IAS 16. The building shell has a purchase price of AED 12,000,000. Decide which further outlays enter the asset''s carrying amount under the directly-attributable-cost rule: site preparation AED 400,000, professional/architect fees AED 600,000, initial delivery & installation AED 200,000 (all directly attributable - capitalize), staff training AED 150,000 and general administrative overhead AED 100,000 (NOT costs of bringing the asset to working condition - expense). Then complete the componentized straight-line depreciation (all nil residual): Building shell (capitalized total / 40 years), MEP & HVAC AED 3,000,000 / 15 years, Fit-out & finishes AED 1,500,000 / 10 years. Fill the shell capitalized cost (B5), each component''s annual depreciation (B9, B10, B11), total annual depreciation (B12), total componentized cost (B15), accumulated depreciation after 3 years (B16) and net book value after 3 years (B17).','تقوم شركة الإمارات كابيتال القابضة (دبي) برسملة تجهيزات مقر رئيسي جديد وفق المعيار المحاسبي الدولي 16. سعر شراء هيكل المبنى 12,000,000 درهم. حدّد أي النفقات الإضافية تدخل في القيمة الدفترية للأصل بموجب قاعدة التكلفة المنسوبة مباشرة: تجهيز الموقع 400,000 درهم، أتعاب مهنية/معمارية 600,000 درهم، التسليم والتركيب الأولي 200,000 درهم (جميعها منسوبة مباشرة - تُرسمل)، تدريب الموظفين 150,000 درهم والمصاريف الإدارية العامة 100,000 درهم (ليست من تكاليف إيصال الأصل لحالة التشغيل - تُحمّل كمصروف). ثم أكمل الإهلاك المجزأ بالقسط الثابت (قيمة متبقية صفرية): هيكل المبنى (الإجمالي المرسمل / 40 سنة)، الأنظمة الكهروميكانيكية والتكييف 3,000,000 درهم / 15 سنة، التشطيبات 1,500,000 درهم / 10 سنوات. أكمل التكلفة المرسملة للهيكل (B5)، الإهلاك السنوي لكل مكوّن (B9، B10، B11)، إجمالي الإهلاك السنوي (B12)، إجمالي التكلفة المجزأة (B15)، مجمع الإهلاك بعد 3 سنوات (B16) والقيمة الدفترية الصافية بعد 3 سنوات (B17).','{"rows":[{"A":"Emirates Capital Holdings - HQ Capitalization (AED)","r":1,"kind":"title"},{"A":"1. Capitalize-vs-Expense (IAS 16 directly attributable)","r":2,"kind":"section"},{"A":"Building shell - purchase price","B":12000000,"r":3,"given":true},{"A":"Add: Site preparation (directly attributable)","B":400000,"r":4,"given":true},{"A":"  Shell capitalized cost (incl. fees & installation)","r":5,"ref":"B5","hint":"=12000000+400000+600000+200000","editable":true},{"A":"  Professional / architect fees (capitalize)","B":600000,"r":6,"given":true},{"A":"  Initial delivery & installation (capitalize)","B":200000,"r":7,"given":true},{"A":"  Staff training (EXPENSE - exclude)","B":150000,"r":8,"given":true},{"A":"2. Componentized annual depreciation (straight-line, nil residual)","r":8,"kind":"section"},{"A":"  Shell depreciation = shell cost / 40 yrs","r":9,"ref":"B9","hint":"=B5/40","editable":true},{"A":"  MEP & HVAC depreciation = 3,000,000 / 15 yrs","r":10,"ref":"B10","hint":"=3000000/15","editable":true},{"A":"  Fit-out depreciation = 1,500,000 / 10 yrs","r":11,"ref":"B11","hint":"=1500000/10","editable":true},{"A":"  Total annual depreciation","r":12,"ref":"B12","hint":"=SUM(B9:B11)","editable":true},{"A":"3. NBV roll-forward after 3 full years","r":13,"kind":"section"},{"A":"  MEP & HVAC component cost","B":3000000,"r":14,"given":true},{"A":"  Total componentized cost (shell + MEP + fit-out)","r":15,"ref":"B15","hint":"=B5+3000000+1500000","editable":true},{"A":"  Accumulated depreciation after 3 years","r":16,"ref":"B16","hint":"=B12*3","editable":true},{"A":"  Net book value after 3 years","r":17,"ref":"B17","hint":"=B15-B16","editable":true}],"currency":"AED","editable":["B5","B9","B10","B11","B12","B15","B16","B17"],"sheetName":"FA-Capex"}'::jsonb,'{"cells":{"B5":13200000,"B9":330000,"B10":200000,"B11":150000,"B12":680000,"B15":17700000,"B16":2040000,"B17":15660000}}'::jsonb,'[{"id":"shell_capitalized","kind":"cell_value","target":"B5","weight":3,"expected":13200000,"label_en":"Shell capitalized cost = AED 13,200,000 (training & admin correctly expensed)","label_ar":"التكلفة المرسملة للهيكل = 13,200,000 درهم (التدريب والإدارة مُحمّلان كمصروف بشكل صحيح)","tolerance":0.01},{"id":"shell_dep","kind":"cell_value","target":"B9","weight":1,"expected":330000,"label_en":"Shell annual depreciation = AED 330,000","label_ar":"الإهلاك السنوي للهيكل = 330,000 درهم","tolerance":0.01},{"id":"total_dep","kind":"cell_value","target":"B12","weight":2,"expected":680000,"label_en":"Total annual depreciation = AED 680,000","label_ar":"إجمالي الإهلاك السنوي = 680,000 درهم","tolerance":0.01},{"id":"nbv_3yr","kind":"cell_value","target":"B17","weight":2,"expected":15660000,"label_en":"Net book value after 3 years = AED 15,660,000","label_ar":"القيمة الدفترية الصافية بعد 3 سنوات = 15,660,000 درهم","tolerance":0.01}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'Reducing-Balance (WDV) Depreciation Sensitivity Table','جدول حساسية الإهلاك بطريقة الرصيد المتناقص (القيمة الدفترية المتناقصة)','','','IAS 16 (diminishing-balance method) / AFP FPAC','advanced_spreadsheet',900,'Qatar National Logistics depreciates a fleet of forklifts (cost AED 2,000,000, nil residual) on the reducing-balance (written-down-value) method and wants a sensitivity surface of closing net book value. Closing NBV = cost x (1 - rate)^year. First build the single-cell engine formula in B5 for the base case (rate 20% in B1, year 3 in B3). Then construct a NATIVE two-variable data table in C9:E11 with depreciation rate down the rows (15%, 20%, 25% in B9:B11) and elapsed years across the columns (1, 2, 3 in C8:E8). The corner cell B8 must link to the engine formula B5. Wire the row input cell to the year (B3) and the column input cell to the rate (B1). The grid must be a real data table, not hardcoded numbers.','تقوم شركة قطر الوطنية للخدمات اللوجستية بإهلاك أسطول رافعات شوكية (التكلفة 2,000,000 درهم، قيمة متبقية صفرية) بطريقة الرصيد المتناقص وترغب في بناء سطح حساسية للقيمة الدفترية الصافية الختامية. القيمة الدفترية الختامية = التكلفة × (1 − المعدل)^السنة. أولاً ابنِ صيغة المحرّك في الخلية B5 للحالة الأساسية (المعدل 20% في B1، السنة 3 في B3). ثم أنشئ جدول بيانات أصلي ثنائي المتغير في النطاق C9:E11 مع معدل الإهلاك على الصفوف (15%، 20%، 25% في B9:B11) والسنوات على الأعمدة (1، 2، 3 في C8:E8). يجب أن ترتبط خلية الزاوية B8 بصيغة المحرّك B5. اربط خلية إدخال الصف بالسنة (B3) وخلية إدخال العمود بالمعدل (B1). يجب أن يكون الجدول جدول بيانات حقيقياً وليس قيماً ثابتة.','{"rows":[{"A":"Depreciation rate (reducing balance)","B":0.2,"r":1,"given":true},{"A":"Asset cost","B":2000000,"r":2,"given":true},{"A":"Elapsed years","B":3,"r":3,"given":true},{"A":"Closing NBV = cost x (1-rate)^year","r":5,"ref":"B5","hint":"=B2*(1-B1)^B3","editable":true},{"A":"Two-variable Data Table: rows=Rate (B9:B11), cols=Year (C8:E8)","r":7,"kind":"section"},{"A":"(corner formula links to closing NBV B5)","r":8,"ref":"B8","hint":"=B5","editable":true},{"C":1,"D":2,"E":3,"r":8,"note":"year headers C8:E8","given":true},{"A":0.15,"r":9,"note":"rate row header","given":true},{"A":0.2,"r":10,"given":true},{"A":0.25,"r":11,"given":true}],"model":{"rate":"B1","cost":"B2","year":"B3","closingNbv":"B5"},"currency":"AED","editable":["B5","B8","C9:E11"],"dataTable":{"range":"C9:E11","corner":"B8","colInput":"B1","rowInput":"B3"},"sheetName":"WDV-Sensitivity"}'::jsonb,'{"cells":{"B5":1024000,"B8":1024000,"C9":1700000,"D10":1280000,"E11":843750}}'::jsonb,'[{"id":"array_formula","kind":"is_array_formula","target":"C9:E11","weight":3,"label_en":"3x3 grid uses a native data table {=TABLE()} (not hardcoded values)","label_ar":"تستخدم الشبكة 3×3 جدول بيانات أصلي {=TABLE()} وليس قيماً ثابتة"},{"id":"corner_low","kind":"cell_value","target":"C9","weight":1,"expected":1700000,"label_en":"Low corner (rate 15%, year 1) = AED 1,700,000","label_ar":"الزاوية الدنيا (معدل 15%، السنة 1) = 1,700,000 درهم","tolerance":0.01},{"id":"center","kind":"cell_value","target":"D10","weight":1,"expected":1280000,"label_en":"Centre (rate 20%, year 2) = AED 1,280,000","label_ar":"المركز (معدل 20%، السنة 2) = 1,280,000 درهم","tolerance":0.01},{"id":"corner_high","kind":"cell_value","target":"E11","weight":1,"expected":843750,"label_en":"High corner (rate 25%, year 3) = AED 843,750","label_ar":"الزاوية العليا (معدل 25%، السنة 3) = 843,750 درهم","tolerance":0.01}]'::jsonb,2);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p2,'IAS 36 Impairment Test - Value in Use vs Fair Value','اختبار اضمحلال القيمة وفق المعيار 36 - القيمة في الاستخدام مقابل القيمة العادلة','','','IAS 36 Impairment of Assets','logic_input',600,'Riyadh Industrial Group is impairment-testing a cash-generating unit (CGU) with a carrying amount of AED 9,500,000. Management projects pre-discount cash flows of AED 1,800,000 (Yr1), 1,900,000 (Yr2), 2,000,000 (Yr3), 2,000,000 (Yr4) and 1,500,000 (Yr5), discounted at a pre-tax rate of 12%. The fair value of the CGU less costs of disposal (FVLCD) is AED 8,200,000. Compute (1) value in use as the discounted cash-flow sum, (2) the recoverable amount as the higher of VIU and FVLCD, (3) the impairment loss (carrying amount less recoverable amount) and (4) the post-impairment carrying amount. Note: VIU is LOWER than FVLCD here, so the recoverable amount must default to FVLCD.','تجري مجموعة الرياض الصناعية اختبار اضمحلال لوحدة مولّدة للنقد قيمتها الدفترية 9,500,000 درهم. تتوقع الإدارة تدفقات نقدية قبل الخصم قدرها 1,800,000 درهم (السنة 1)، 1,900,000 (السنة 2)، 2,000,000 (السنة 3)، 2,000,000 (السنة 4)، 1,500,000 (السنة 5)، مخصومة بمعدل قبل الضريبة 12%. القيمة العادلة للوحدة ناقصاً تكاليف الاستبعاد 8,200,000 درهم. احسب: (1) القيمة في الاستخدام كمجموع التدفقات المخصومة، (2) المبلغ القابل للاسترداد كأعلى القيمتين، (3) خسارة الاضمحلال (القيمة الدفترية ناقصاً المبلغ القابل للاسترداد)، (4) القيمة الدفترية بعد الاضمحلال. ملاحظة: القيمة في الاستخدام هنا أقل من القيمة العادلة، لذا يجب أن يكون المبلغ القابل للاسترداد هو القيمة العادلة.','{"fields":[{"id":"value_in_use","type":"number","label_en":"Value in Use - discounted CF sum (AED)","label_ar":"القيمة في الاستخدام - مجموع التدفقات المخصومة (درهم)"},{"id":"recoverable_amount","type":"number","label_en":"Recoverable Amount = max(VIU, FVLCD) (AED)","label_ar":"المبلغ القابل للاسترداد = الأعلى من القيمتين (درهم)"},{"id":"impairment_loss","type":"number","label_en":"Impairment Loss (AED)","label_ar":"خسارة اضمحلال القيمة (درهم)"},{"id":"post_impairment_ca","type":"number","label_en":"Post-impairment carrying amount (AED)","label_ar":"القيمة الدفترية بعد الاضمحلال (درهم)"}],"scenario":{"note_en":"Apply the IAS 36 mechanic: discount projected cash flows to value in use at 12%, take the recoverable amount as the higher of VIU and FVLCD, then book the impairment loss against the carrying amount.","note_ar":"طبّق آلية المعيار 36: اخصم التدفقات النقدية المتوقعة إلى القيمة في الاستخدام بمعدل 12%، وخذ المبلغ القابل للاسترداد كأعلى من القيمة في الاستخدام والقيمة العادلة، ثم احسب خسارة الاضمحلال مقابل القيمة الدفترية.","carrying_amount":9500000,"discount_rate":0.12,"fair_value_less_costs_of_disposal":8200000,"cash_flows":[{"year":1,"amount":1800000},{"year":2,"amount":1900000},{"year":3,"amount":2000000},{"year":4,"amount":2000000},{"year":5,"amount":1500000}]}}'::jsonb,'{"fields":{"value_in_use":6667548,"recoverable_amount":8200000,"impairment_loss":1300000,"post_impairment_ca":8200000}}'::jsonb,'[{"id":"viu","kind":"logic_value","field":"value_in_use","weight":2,"expected":6667548,"label_en":"Value in use (discounted CF sum) approx AED 6,667,548","label_ar":"القيمة في الاستخدام (مجموع التدفقات المخصومة) نحو 6,667,548 درهم","tolerance":500},{"id":"recoverable","kind":"logic_value","field":"recoverable_amount","weight":3,"expected":8200000,"label_en":"Recoverable amount = AED 8,200,000 (higher of VIU and FVLCD)","label_ar":"المبلغ القابل للاسترداد = 8,200,000 درهم (الأعلى من القيمتين)","tolerance":1},{"id":"loss","kind":"logic_value","field":"impairment_loss","weight":2,"expected":1300000,"label_en":"Impairment loss = AED 1,300,000","label_ar":"خسارة الاضمحلال = 1,300,000 درهم","tolerance":1},{"id":"post_ca","kind":"logic_value","field":"post_impairment_ca","weight":1,"expected":8200000,"label_en":"Post-impairment carrying amount = AED 8,200,000","label_ar":"القيمة الدفترية بعد الاضمحلال = 8,200,000 درهم","tolerance":1}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p3,'Fixed Asset Register - Net Book Value by Category','سجل الأصول الثابتة - القيمة الدفترية الصافية حسب الفئة','','','DAMA DMBOK / IAS 16 disclosure (PP&E by class)','sql',600,'A GCC manufacturer maintains its fixed asset register in asset_register (id, asset_code, category, cost, accum_depreciation, status), where status is ''active'', ''disposed'' or ''fully_depreciated''. For the IAS 16 PP&E disclosure, return the net book value (cost minus accumulated depreciation) totalled per asset category - but ONLY for assets that are still active; disposed and fully-depreciated assets must be excluded. Return columns category and total_nbv, highest NBV first.','تحتفظ إحدى شركات التصنيع الخليجية بسجل أصولها الثابتة في الجدول asset_register (id, asset_code, category, cost, accum_depreciation, status)، حيث تكون الحالة ''active'' أو ''disposed'' أو ''fully_depreciated''. للإفصاح وفق المعيار 16، أعد القيمة الدفترية الصافية (التكلفة ناقصاً مجمع الإهلاك) مجمّعة لكل فئة أصول - فقط للأصول النشطة؛ يجب استبعاد الأصول المستبعدة والمهلكة بالكامل. أعد العمودين category و total_nbv، الأعلى قيمةً أولاً.','{"dialect":"postgres","schema_sql":"CREATE TABLE asset_register (id int PRIMARY KEY, asset_code text, category text, cost numeric, accum_depreciation numeric, status text);","seed_sql":"INSERT INTO asset_register (id, asset_code, category, cost, accum_depreciation, status) VALUES (1,''BLD-001'',''Buildings'',9000000,1200000,''active''),(2,''BLD-002'',''Buildings'',5000000,1640000,''active''),(3,''BLD-003'',''Buildings'',2000000,2000000,''fully_depreciated''),(4,''PLM-001'',''Plant & Machinery'',3000000,800000,''active''),(5,''PLM-002'',''Plant & Machinery'',2500000,424000,''active''),(6,''FIT-001'',''Fit-out'',1500000,300000,''active''),(7,''FIT-002'',''Fit-out'',900000,330000,''active''),(8,''ITE-001'',''IT Equipment'',500000,310000,''active''),(9,''ITE-002'',''IT Equipment'',250000,100000,''active''),(10,''ITE-003'',''IT Equipment'',400000,150000,''disposed''),(11,''MTV-001'',''Motor Vehicles'',300000,180000,''active''),(12,''MTV-002'',''Motor Vehicles'',200000,72000,''active'');","prompt_en":"Write a query returning net book value (cost - accum_depreciation) totalled per category for ACTIVE assets only, highest NBV first. Columns: category, total_nbv.","prompt_ar":"اكتب استعلاماً يُرجع القيمة الدفترية الصافية (التكلفة − مجمع الإهلاك) مجمّعة لكل فئة للأصول النشطة فقط، الأعلى قيمةً أولاً. الأعمدة: category, total_nbv."}'::jsonb,'{"master_query":"SELECT category, SUM(cost - accum_depreciation) AS total_nbv FROM asset_register WHERE status = ''active'' GROUP BY category ORDER BY total_nbv DESC, category"}'::jsonb,'[{"id":"result_match","kind":"sql_result_match","weight":3,"ordered":true,"label_en":"Result matches master: active-only NBV per category, highest first","label_ar":"تطابق النتيجة النموذج: القيمة الدفترية الصافية للأصول النشطة فقط لكل فئة، الأعلى أولاً"}]'::jsonb,1);
  UPDATE technical_functions SET node_status='active' WHERE id = fn;
END $$;

-- 1.6 Payroll Operations & Tax Compliance
DO $$
DECLARE fn uuid; p1 uuid; p2 uuid; p3 uuid;
BEGIN
  SELECT id INTO fn FROM technical_functions WHERE node_id='1.6';
  IF fn IS NULL THEN RAISE NOTICE 'function 1.6 not found, skipping'; RETURN; END IF;
  DELETE FROM technical_pillars WHERE function_id = fn;  -- re-runnable (cascades to blocks)
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Gross-to-Net Payroll Processing & Controls','معالجة الرواتب من الإجمالي إلى الصافي والضوابط',1) RETURNING id INTO p1;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Statutory Settlements & End-of-Service Benefits','التسويات النظامية ومكافأة نهاية الخدمة',2) RETURNING id INTO p2;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Payroll Reconciliation & Cost Interrogation','تسوية الرواتب واستجواب التكاليف',3) RETURNING id INTO p3;
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'GCC Monthly Payroll Register & WPS Control Total','سجل الرواتب الشهري الخليجي وإجمالي الرقابة لنظام حماية الأجور','','','Saudi GOSI Social Insurance Law / SAMA WPS (Wage Protection System) / IMA Payroll Control Standards','spreadsheet',1000,'Al-Faisaliah Trading Co (Riyadh, KSA) is running its March payroll for a 4-employee cohort (amounts in SAR). For each employee compute: (1) GOSI base = Basic + Housing only (Transport, Overtime and Unpaid-Leave are excluded; base is capped at a SAR 45,000 ceiling - no row breaches it here); (2) Employee GOSI deduction = GOSI base x 9.75% for Saudi nationals, and 0 for non-Saudi nationals (the employer pays 2% occupational hazard for non-Saudis, which is not deducted from the employee and not required here); (3) Gross Earnings = Basic + Housing + Transport + Overtime - Unpaid-Leave; (4) Net Pay = Gross Earnings - Employee GOSI. Finally compute the WPS-payable control total = the sum of all four Net Pay figures (the amount that must hit the SAMA WPS bank file). Fill every shaded cell.','تُجري شركة الفيصلية التجارية (الرياض، السعودية) رواتب شهر مارس لأربعة موظفين (المبالغ بالريال السعودي). لكل موظف احسب: (1) وعاء التأمينات (جوسي) = الراتب الأساسي + بدل السكن فقط (تُستبعد بدلات النقل والعمل الإضافي وخصم الإجازة بدون أجر؛ والوعاء محدود بسقف 45,000 ريال - ولا يتجاوزه أي صف هنا)؛ (2) خصم التأمينات على الموظف = وعاء التأمينات × 9.75% للسعوديين، و0 لغير السعوديين (يدفع صاحب العمل 2% أخطار مهنية لغير السعوديين ولا يُخصم من الموظف ولا يُطلب هنا)؛ (3) إجمالي الأجر = الأساسي + السكن + النقل + العمل الإضافي - الإجازة بدون أجر؛ (4) صافي الراتب = إجمالي الأجر - خصم التأمينات. وأخيرًا احسب إجمالي الرقابة المستحق لنظام حماية الأجور = مجموع صافي رواتب الموظفين الأربعة (المبلغ الذي يجب أن يصل ملف ساما للأجور). املأ كل خلية مظللة.','{"rows":[{"A":"Al-Faisaliah Trading Co - March Payroll Register (SAR)","r":1,"kind":"title"},{"A":"E1  Ahmed Al-Saud  (Saudi)","r":3,"kind":"section"},{"A":"  Basic Salary","B":20000,"r":4,"given":true},{"A":"  Housing Allowance","B":5000,"r":5,"given":true},{"A":"  Transport Allowance","B":800,"r":6,"given":true},{"A":"  Overtime (attendance-adjusted)","B":1200,"r":7,"given":true},{"A":"  Unpaid-Leave Deduction","B":0,"r":8,"given":true},{"A":"  GOSI base (Basic + Housing)","r":9,"ref":"B9","hint":"=B4+B5","editable":true},{"A":"  Employee GOSI (9.75% Saudi)","r":10,"ref":"B10","hint":"=B9*0.0975","editable":true},{"A":"  Gross Earnings","r":11,"ref":"B11","hint":"=B4+B5+B6+B7-B8","editable":true},{"A":"  Net Pay (Gross - Employee GOSI)","r":12,"ref":"B12","hint":"=B11-B10","editable":true},{"A":"E2  Fatima Al-Harbi  (Saudi)","r":14,"kind":"section"},{"A":"  Basic Salary","B":12000,"r":15,"given":true},{"A":"  Housing Allowance","B":3000,"r":16,"given":true},{"A":"  Transport Allowance","B":800,"r":17,"given":true},{"A":"  Overtime (attendance-adjusted)","B":0,"r":18,"given":true},{"A":"  Unpaid-Leave Deduction","B":1500,"r":19,"given":true},{"A":"  GOSI base (Basic + Housing)","r":20,"ref":"B20","hint":"=B15+B16","editable":true},{"A":"  Employee GOSI (9.75% Saudi)","r":21,"ref":"B21","hint":"=B20*0.0975","editable":true},{"A":"  Gross Earnings","r":22,"ref":"B22","hint":"=B15+B16+B17+B18-B19","editable":true},{"A":"  Net Pay (Gross - Employee GOSI)","r":23,"ref":"B23","hint":"=B22-B21","editable":true},{"A":"E3  Rajesh Kumar  (non-Saudi)","r":25,"kind":"section"},{"A":"  Basic Salary","B":9000,"r":26,"given":true},{"A":"  Housing Allowance","B":2000,"r":27,"given":true},{"A":"  Transport Allowance","B":600,"r":28,"given":true},{"A":"  Overtime (attendance-adjusted)","B":900,"r":29,"given":true},{"A":"  Unpaid-Leave Deduction","B":0,"r":30,"given":true},{"A":"  GOSI base (Basic + Housing)","r":31,"ref":"B31","hint":"=B26+B27","editable":true},{"A":"  Employee GOSI (0 for non-Saudi)","r":32,"ref":"B32","hint":"=0","editable":true},{"A":"  Gross Earnings","r":33,"ref":"B33","hint":"=B26+B27+B28+B29-B30","editable":true},{"A":"  Net Pay (Gross - Employee GOSI)","r":34,"ref":"B34","hint":"=B33-B32","editable":true},{"A":"E4  Maria Santos  (non-Saudi)","r":36,"kind":"section"},{"A":"  Basic Salary","B":7000,"r":37,"given":true},{"A":"  Housing Allowance","B":1500,"r":38,"given":true},{"A":"  Transport Allowance","B":600,"r":39,"given":true},{"A":"  Overtime (attendance-adjusted)","B":0,"r":40,"given":true},{"A":"  Unpaid-Leave Deduction","B":700,"r":41,"given":true},{"A":"  GOSI base (Basic + Housing)","r":42,"ref":"B42","hint":"=B37+B38","editable":true},{"A":"  Employee GOSI (0 for non-Saudi)","r":43,"ref":"B43","hint":"=0","editable":true},{"A":"  Gross Earnings","r":44,"ref":"B44","hint":"=B37+B38+B39+B40-B41","editable":true},{"A":"  Net Pay (Gross - Employee GOSI)","r":45,"ref":"B45","hint":"=B44-B43","editable":true},{"A":"WPS Control Total","r":47,"kind":"section"},{"A":"  WPS-payable total (sum of Net Pay)","r":48,"ref":"B48","hint":"=B12+B23+B34+B45","editable":true}],"currency":"SAR","editable":["B9","B10","B11","B12","B20","B21","B22","B23","B31","B32","B33","B34","B42","B43","B44","B45","B48"],"sheetName":"Payroll"}'::jsonb,'{"cells":{"B9":25000,"B10":2437.5,"B11":27000,"B12":24562.5,"B20":15000,"B21":1462.5,"B22":14300,"B23":12837.5,"B31":11000,"B32":0,"B33":12500,"B34":12500,"B42":8500,"B43":0,"B44":8700,"B45":8700,"B48":58600}}'::jsonb,'[{"id":"e1_gosi","kind":"cell_value","target":"B10","weight":2,"expected":2437.5,"label_en":"E1 employee GOSI = 2437.5 (Saudi, 9.75% of Basic+Housing)","label_ar":"تأمينات الموظف E1 = 2437.5 (سعودي، 9.75% من الأساسي+السكن)","tolerance":0.01},{"id":"e1_net","kind":"cell_value","target":"B12","weight":1,"expected":24562.5,"label_en":"E1 net pay = 24562.5 (Saudi gross-to-net with overtime)","label_ar":"صافي راتب E1 = 24562.5 (سعودي من الإجمالي للصافي مع العمل الإضافي)","tolerance":0.01},{"id":"e2_net","kind":"cell_value","target":"B23","weight":2,"expected":12837.5,"label_en":"E2 net pay = 12837.5 (unpaid leave applied)","label_ar":"صافي راتب E2 = 12837.5 (تطبيق خصم الإجازة بدون أجر)","tolerance":0.01},{"id":"e3_gosi","kind":"cell_value","target":"B32","weight":2,"expected":0,"label_en":"E3 employee GOSI = 0 (non-Saudi: no employee deduction)","label_ar":"تأمينات الموظف E3 = 0 (غير سعودي: لا يوجد خصم على الموظف)","tolerance":0.01},{"id":"e4_net","kind":"cell_value","target":"B45","weight":1,"expected":8700,"label_en":"E4 net pay = 8700 (non-Saudi with attendance adjustment)","label_ar":"صافي راتب E4 = 8700 (غير سعودي مع تعديل الحضور)","tolerance":0.01},{"id":"wps_total","kind":"cell_value","target":"B48","weight":3,"expected":58600,"label_en":"WPS-payable control total = 58600 (cohort net-pay rollup)","label_ar":"إجمالي الرقابة المستحق لحماية الأجور = 58600 (إجمالي صافي رواتب المجموعة)","tolerance":0.01}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p2,'UAE End-of-Service Gratuity Settlement (Decree-Law 33/2021)','تسوية مكافأة نهاية الخدمة الإماراتية (المرسوم بقانون 33/2021)','','','UAE Federal Decree-Law No. 33 of 2021 (Labour Law), Art. 51 - End-of-Service Gratuity','logic_input',600,'An employee at Emirates Gulf Logistics (Dubai) resigns after completing exactly 7.5 years of continuous unlimited-term service. Final basic salary (gratuity is computed on BASIC only, excluding allowances) is AED 18,000/month. Apply UAE Federal Decree-Law 33/2021: for the FIRST 5 years of service the gratuity accrues at 21 days of basic wage per year; for EACH year BEYOND 5 years it accrues at 30 days of basic wage per year; fractional years are paid pro-rata. Daily wage = monthly basic / 30. The total gratuity is capped at 2 years'' total basic wage (24 months of basic). Compute: (1) daily wage; (2) gratuity earned for the first 5 years; (3) gratuity earned for the years beyond 5 (the remaining 2.5 years); (4) total gratuity before the cap; (5) the final payable after applying the 2-year cap.','يستقيل موظف في شركة الإمارات الخليجية للخدمات اللوجستية (دبي) بعد إتمام 7.5 سنوات بالضبط من الخدمة المستمرة غير محددة المدة. الراتب الأساسي النهائي (تُحسب المكافأة على الأساسي فقط دون البدلات) هو 18,000 درهم/شهر. طبّق المرسوم بقانون اتحادي 33/2021: عن أول 5 سنوات تُستحق المكافأة بواقع 21 يومًا من الأجر الأساسي عن كل سنة؛ وعن كل سنة بعد 5 سنوات بواقع 30 يومًا عن كل سنة؛ وتُدفع كسور السنة بالتناسب. الأجر اليومي = الأساسي الشهري / 30. ويُحدد إجمالي المكافأة بسقف أجر سنتين (24 شهرًا من الأساسي). احسب: (1) الأجر اليومي؛ (2) مكافأة أول 5 سنوات؛ (3) مكافأة السنوات بعد 5 (الـ 2.5 سنة المتبقية)؛ (4) إجمالي المكافأة قبل السقف؛ (5) المبلغ النهائي المستحق بعد تطبيق سقف السنتين.','{"fields":[{"id":"daily_wage","type":"number","label_en":"Daily wage (AED, = monthly basic / 30)","label_ar":"الأجر اليومي (درهم، = الأساسي الشهري / 30)"},{"id":"first5_gratuity","type":"number","label_en":"Gratuity for first 5 years (AED, 21 days/yr)","label_ar":"مكافأة أول 5 سنوات (درهم، 21 يومًا/سنة)"},{"id":"beyond5_gratuity","type":"number","label_en":"Gratuity beyond 5 years (AED, 2.5 yrs x 30 days)","label_ar":"مكافأة ما بعد 5 سنوات (درهم، 2.5 سنة × 30 يومًا)"},{"id":"total_before_cap","type":"number","label_en":"Total gratuity before cap (AED)","label_ar":"إجمالي المكافأة قبل السقف (درهم)"},{"id":"final_payable","type":"number","label_en":"Final payable after 2-year cap (AED)","label_ar":"المبلغ النهائي المستحق بعد سقف السنتين (درهم)"}],"scenario":{"note_en":"Compute the UAE end-of-service gratuity for 7.5 years of service on AED 18,000/month basic. First 5 years = 21 days/year; years beyond 5 = 30 days/year; fractional years pro-rata; daily wage = monthly basic / 30; total capped at 24 months of basic.","note_ar":"احسب مكافأة نهاية الخدمة الإماراتية عن 7.5 سنوات خدمة على أساسي 18,000 درهم/شهر. أول 5 سنوات = 21 يومًا/سنة؛ السنوات بعد 5 = 30 يومًا/سنة؛ كسور السنة بالتناسب؛ الأجر اليومي = الأساسي الشهري / 30؛ والإجمالي محدود بسقف 24 شهرًا من الأساسي.","years_of_service":7.5,"monthly_basic_aed":18000,"days_factor_first5":21,"days_factor_beyond5":30,"first5_threshold_years":5,"days_per_month_divisor":30,"cap_months_of_basic":24}}'::jsonb,'{"fields":{"daily_wage":600,"first5_gratuity":63000,"beyond5_gratuity":45000,"total_before_cap":108000,"final_payable":108000}}'::jsonb,'[{"id":"daily","kind":"logic_value","field":"daily_wage","weight":1,"expected":600,"label_en":"Daily wage = 600 (monthly basic / 30)","label_ar":"الأجر اليومي = 600 (الأساسي الشهري / 30)","tolerance":0.5},{"id":"first5","kind":"logic_value","field":"first5_gratuity","weight":2,"expected":63000,"label_en":"First-5-years gratuity = 63000 (21-day tier)","label_ar":"مكافأة أول 5 سنوات = 63000 (شريحة 21 يومًا)","tolerance":1},{"id":"beyond5","kind":"logic_value","field":"beyond5_gratuity","weight":3,"expected":45000,"label_en":"Beyond-5-years gratuity = 45000 (2.5 yrs x 30 days, pro-rata)","label_ar":"مكافأة ما بعد 5 سنوات = 45000 (2.5 سنة × 30 يومًا، بالتناسب)","tolerance":1},{"id":"total","kind":"logic_value","field":"total_before_cap","weight":2,"expected":108000,"label_en":"Total before cap = 108000 (two-tier accrual)","label_ar":"الإجمالي قبل السقف = 108000 (استحقاق على شريحتين)","tolerance":1},{"id":"final","kind":"logic_value","field":"final_payable","weight":2,"expected":108000,"label_en":"Final payable after 2-year cap = 108000 (cap does not bind)","label_ar":"المبلغ النهائي بعد سقف السنتين = 108000 (السقف غير ملزم هنا)","tolerance":1}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p2,'Gratuity Liability Sensitivity Matrix (Tenure x Final Salary)','مصفوفة حساسية التزام مكافأة نهاية الخدمة (مدة الخدمة × الراتب النهائي)','','','IAS 19 Employee Benefits (end-of-service provisioning) / UAE Federal Decree-Law No. 33 of 2021','advanced_spreadsheet',900,'The finance team at Emirates Gulf Logistics must provision the end-of-service liability for a senior hire across scenarios for the IAS 19 accrual. The driver cell B5 computes total gratuity (AED, before the 2-year cap) using the same UAE rule as the settlement block: daily wage = monthly basic / 30; first 5 years at 21 days/year; each year beyond 5 at 30 days/year; pro-rata fractions. The base inputs are Years of service (B3 = 6) and Final monthly basic (B1 = 20000). Build a two-variable data table over the range C9:E11 where the ROW headers (A9:A11) are years of service {3, 6, 9} and the COLUMN headers (C8:E8) are final monthly basic {15000, 20000, 25000}. The table MUST be produced with a native two-variable data table (array formula) driven off the single gratuity formula in B5 (corner B8 = B5) - not hardcoded numbers.','يجب على فريق المالية في شركة الإمارات الخليجية للخدمات اللوجستية رصد مخصص التزام نهاية الخدمة لموظف كبير عبر عدة سيناريوهات لاستحقاق المعيار الدولي IAS 19. تحسب الخلية المحركة B5 إجمالي المكافأة (درهم، قبل سقف السنتين) بنفس قاعدة الإمارات: الأجر اليومي = الأساسي الشهري / 30؛ أول 5 سنوات بواقع 21 يومًا/سنة؛ وكل سنة بعد 5 بواقع 30 يومًا/سنة؛ مع كسور تناسبية. المدخلات الأساسية: سنوات الخدمة (B3 = 6) والأساسي الشهري النهائي (B1 = 20000). أنشئ جدول بيانات بمتغيرين في النطاق C9:E11 حيث رؤوس الصفوف (A9:A11) هي سنوات الخدمة {3، 6، 9} ورؤوس الأعمدة (C8:E8) هي الأساسي الشهري النهائي {15000، 20000، 25000}. يجب إنشاء الجدول عبر جدول بيانات أصلي بمتغيرين (معادلة مصفوفية) مرتبط بمعادلة المكافأة الوحيدة في B5 (الزاوية B8 = B5) - وليس بأرقام ثابتة.','{"rows":[{"A":"Final monthly basic (AED)","B":20000,"r":1,"given":true},{"A":"Daily wage  =MonthlyBasic/30","B":666.6666666666666,"r":2,"given":true},{"A":"Years of service","B":6,"r":3,"given":true},{"A":"Gratuity driver  =MIN(yrs,5)*21*(basic/30)+MAX(yrs-5,0)*30*(basic/30)","r":5,"ref":"B5","hint":"=MIN(B3,5)*21*(B1/30)+MAX(B3-5,0)*30*(B1/30)","editable":true},{"A":"Two-variable Data Table: rows=Years, cols=Final basic","r":7,"kind":"section"},{"A":"(corner formula links to gratuity driver)","r":8,"hint":"=B5","B7ref":"B8","editable":true},{"C":15000,"D":20000,"E":25000,"r":8,"note":"final-basic headers C8:E8","given":true},{"A":3,"r":9,"note":"years row header","given":true},{"A":6,"r":10,"given":true},{"A":9,"r":11,"given":true}],"model":{"finalBasic":"B1","dailyWage":"B2","years":"B3","gratuity":"B5"},"currency":"AED","editable":["B5","B8","C9:E11"],"dataTable":{"range":"C9:E11","corner":"B8","colInput":"B1","rowInput":"B3"},"sheetName":"Sensitivity"}'::jsonb,'{"cells":{"B5":90000,"B8":90000,"C9":31500,"D9":42000,"E9":52500,"C10":67500,"D10":90000,"E10":112500,"C11":112500,"D11":150000,"E11":187500}}'::jsonb,'[{"id":"array_formula","kind":"is_array_formula","target":"C9:E11","weight":3,"label_en":"Sensitivity grid uses a native two-variable data table (not hardcoded)","label_ar":"تستخدم شبكة الحساسية جدول بيانات أصليًا بمتغيرين (وليس قيمًا ثابتة)"},{"id":"driver","kind":"cell_value","target":"B5","weight":2,"expected":90000,"label_en":"Driver gratuity cell = 90000 (base case: 6 yrs, AED 20000)","label_ar":"خلية المكافأة المحركة = 90000 (الحالة الأساسية: 6 سنوات، 20000 درهم)","tolerance":0.01},{"id":"low_corner","kind":"cell_value","target":"C9","weight":1,"expected":31500,"label_en":"Low corner (3 yrs, 15000) = 31500","label_ar":"الزاوية الدنيا (3 سنوات، 15000) = 31500","tolerance":0.01},{"id":"high_corner","kind":"cell_value","target":"E11","weight":2,"expected":187500,"label_en":"High corner (9 yrs, 25000) = 187500","label_ar":"الزاوية العليا (9 سنوات، 25000) = 187500","tolerance":0.01},{"id":"interior","kind":"cell_value","target":"C10","weight":1,"expected":67500,"label_en":"Interior (6 yrs, 15000) = 67500 (cross-tier: 5 yrs @21d + 1 yr @30d)","label_ar":"خلية داخلية (6 سنوات، 15000) = 67500 (عبر الشريحتين: 5 سنوات بـ21 يومًا + سنة بـ30 يومًا)","tolerance":0.01}]'::jsonb,2);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p3,'Payroll Ledger Reconciliation & Deduction-Ceiling Breach','تسوية دفتر الرواتب وتجاوز سقف الخصومات','','','Saudi GOSI Social Insurance Law / DAMA DMBOK (data interrogation) / payroll control reconciliation','sql',600,'You are reconciling Al-Faisaliah Trading Co''s payroll run against the statutory deduction ceiling. The table payroll_lines(id, employee, department, nationality, gross_pay, gosi_employee, other_deductions, net_pay) holds one row per employee. Policy control: an employee''s TOTAL deductions (gosi_employee + other_deductions) must never exceed 35% of gross_pay - any row above that is a control breach to escalate before the WPS file is released. Write ONE query that returns every breaching employee with the columns employee, department, gross_pay, and total_deductions (= gosi_employee + other_deductions), ordered by total_deductions highest first, then by employee.','أنت تُسوّي تشغيل رواتب شركة الفيصلية التجارية مقابل سقف الخصومات النظامي. يحتوي الجدول payroll_lines(id, employee, department, nationality, gross_pay, gosi_employee, other_deductions, net_pay) على صف واحد لكل موظف. ضابط السياسة: يجب ألا تتجاوز إجمالي خصومات الموظف (gosi_employee + other_deductions) نسبة 35% من gross_pay - وأي صف يتجاوز ذلك يُعد تجاوزًا رقابيًا يجب تصعيده قبل إصدار ملف حماية الأجور. اكتب استعلامًا واحدًا يُرجع كل موظف متجاوز بالأعمدة employee و department و gross_pay و total_deductions (= gosi_employee + other_deductions)، مرتبًا حسب total_deductions من الأعلى إلى الأدنى ثم حسب employee.','{"dialect":"postgres","schema_sql":"CREATE TABLE payroll_lines (id int PRIMARY KEY, employee text, department text, nationality text, gross_pay numeric, gosi_employee numeric, other_deductions numeric, net_pay numeric);","seed_sql":"INSERT INTO payroll_lines (id, employee, department, nationality, gross_pay, gosi_employee, other_deductions, net_pay) VALUES (1,''Ahmed Al-Saud'',''Sales'',''Saudi'',27000,2437.5,1500,23062.5),(2,''Fatima Al-Harbi'',''Sales'',''Saudi'',14300,1462.5,800,12037.5),(3,''Rajesh Kumar'',''Ops'',''non-Saudi'',12500,0,5000,7500),(4,''Maria Santos'',''Ops'',''non-Saudi'',8700,0,3200,5500),(5,''Khalid Al-Otaibi'',''Finance'',''Saudi'',16000,1560,4500,9940),(6,''Sara Mansour'',''Finance'',''Saudi'',9000,877.5,2600,5522.5);","prompt_en":"Return every employee whose total deductions (gosi_employee + other_deductions) exceed 35% of gross_pay. Columns: employee, department, gross_pay, total_deductions. Order by total_deductions descending, then employee ascending.","prompt_ar":"أرجع كل موظف تتجاوز إجمالي خصوماته (gosi_employee + other_deductions) نسبة 35% من gross_pay. الأعمدة: employee و department و gross_pay و total_deductions. رتّب حسب total_deductions تنازليًا ثم حسب employee تصاعديًا."}'::jsonb,'{"master_query":"SELECT employee, department, gross_pay, gosi_employee + other_deductions AS total_deductions FROM payroll_lines WHERE (gosi_employee + other_deductions) > 0.35 * gross_pay ORDER BY total_deductions DESC, employee"}'::jsonb,'[{"id":"result_match","kind":"sql_result_match","weight":3,"ordered":true,"label_en":"Returns exactly the 4 breaching employees with correct total_deductions, ordered highest first","label_ar":"يُرجع بالضبط الموظفين الأربعة المتجاوزين مع إجمالي خصومات صحيح، مرتبًا من الأعلى أولاً"}]'::jsonb,1);
  UPDATE technical_functions SET node_status='active' WHERE id = fn;
END $$;

-- 1.8 Treasury &amp; Cash Management
DO $$
DECLARE fn uuid; p1 uuid; p2 uuid; p3 uuid;
BEGIN
  SELECT id INTO fn FROM technical_functions WHERE node_id='1.8';
  IF fn IS NULL THEN RAISE NOTICE 'function 1.8 not found, skipping'; RETURN; END IF;
  DELETE FROM technical_pillars WHERE function_id = fn;  -- re-runnable (cascades to blocks)
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Liquidity & Cash Forecasting','إدارة السيولة والتنبؤ النقدي',1) RETURNING id INTO p1;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Market Risk Quantification (FX & Interest Rate)','قياس مخاطر السوق (الصرف الأجنبي وأسعار الفائدة)',2) RETURNING id INTO p2;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Banking Data Interrogation','استجواب البيانات المصرفية',3) RETURNING id INTO p3;
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'Rolling Direct Cash-Flow Forecast & Funding Shortfall','التنبؤ النقدي المباشر المتجدد وعجز التمويل','','','AFP Certified Treasury Professional (CTP) / Association of Corporate Treasurers (ACT)','spreadsheet',1000,'VIFM Logistics LLC (Dubai) runs a 3-month direct (receipts-and-disbursements) cash forecast in AED 000s. Opening cash for Month 1 is 5,000. For each month compute Net Cash Movement = Collections − Operating Disbursements − Payroll (WPS) − Capex, then roll the closing balance forward so each month''s opening equals the prior month''s closing. Finally size the Peak Funding Shortfall: the largest amount by which any month''s closing cash falls below the Board''s minimum operating buffer of 3,000 (i.e. MAX of MAX(0, 3,000 − closing) across the three months) so Treasury can size the revolving credit facility (RCF) drawdown. Fill every highlighted cell.','تدير شركة VIFM للخدمات اللوجستية (دبي) تنبؤًا نقديًا مباشرًا لمدة 3 أشهر بآلاف الدراهم. الرصيد النقدي الافتتاحي للشهر الأول هو 5,000. لكل شهر احسب صافي الحركة النقدية = التحصيلات − المدفوعات التشغيلية − الرواتب (نظام حماية الأجور) − النفقات الرأسمالية، ثم رحّل الرصيد الختامي بحيث يصبح افتتاح كل شهر مساويًا لختام الشهر السابق. وأخيرًا حدد ذروة عجز التمويل: أكبر مبلغ ينخفض به الرصيد النقدي الختامي لأي شهر دون الحد الأدنى للاحتياطي التشغيلي المعتمد من مجلس الإدارة وهو 3,000 (أي القيمة العظمى لـ MAX(0, 3,000 − الرصيد الختامي) عبر الأشهر الثلاثة) حتى تتمكن الخزينة من تحديد حجم السحب على التسهيل الائتماني المتجدد. املأ كل خلية مظللة.','{"rows":[{"A":"VIFM Logistics LLC — 3-Month Direct Cash Forecast (AED 000s)","r":1,"kind":"title"},{"A":"Minimum operating cash buffer (Board mandate)","B":3000,"r":2,"given":true},{"A":"Month 1","r":4,"kind":"section"},{"A":"  Opening cash","B":5000,"r":5,"given":true},{"A":"  Collections","B":12400,"r":6,"given":true},{"A":"  Operating disbursements (AP & opex)","B":-9800,"r":7,"given":true},{"A":"  Payroll (WPS)","B":-3200,"r":8,"given":true},{"A":"  Capex","B":-1500,"r":9,"given":true},{"A":"  Net cash movement","r":10,"ref":"B10","hint":"=SUM(B6:B9)","editable":true},{"A":"  Closing cash","r":11,"ref":"B11","hint":"=B5+B10","editable":true},{"A":"  Shortfall vs buffer = MAX(0, buffer − closing)","r":12,"ref":"B12","hint":"=MAX(0,B2-B11)","editable":true},{"A":"Month 2","r":14,"kind":"section"},{"A":"  Opening cash (roll from M1 closing)","r":15,"ref":"B15","hint":"=B11","editable":true},{"A":"  Collections","B":14200,"r":16,"given":true},{"A":"  Operating disbursements (AP & opex)","B":-10500,"r":17,"given":true},{"A":"  Payroll (WPS)","B":-3200,"r":18,"given":true},{"A":"  Capex","B":-800,"r":19,"given":true},{"A":"  Net cash movement","r":20,"ref":"B20","hint":"=SUM(B16:B19)","editable":true},{"A":"  Closing cash","r":21,"ref":"B21","hint":"=B15+B20","editable":true},{"A":"  Shortfall vs buffer = MAX(0, buffer − closing)","r":22,"ref":"B22","hint":"=MAX(0,B2-B21)","editable":true},{"A":"Month 3","r":24,"kind":"section"},{"A":"  Opening cash (roll from M2 closing)","r":25,"ref":"B25","hint":"=B21","editable":true},{"A":"  Collections","B":16800,"r":26,"given":true},{"A":"  Operating disbursements (AP & opex)","B":-11200,"r":27,"given":true},{"A":"  Payroll (WPS)","B":-3400,"r":28,"given":true},{"A":"  Capex","B":-2000,"r":29,"given":true},{"A":"  Net cash movement","r":30,"ref":"B30","hint":"=SUM(B26:B29)","editable":true},{"A":"  Closing cash","r":31,"ref":"B31","hint":"=B25+B30","editable":true},{"A":"  Shortfall vs buffer = MAX(0, buffer − closing)","r":32,"ref":"B32","hint":"=MAX(0,B2-B31)","editable":true},{"A":"RCF Sizing","r":34,"kind":"section"},{"A":"  Peak funding shortfall (RCF drawdown)","r":35,"ref":"B35","hint":"=MAX(B12,B22,B32)","editable":true}],"currency":"AED 000s","editable":["B10","B11","B12","B15","B20","B21","B22","B25","B30","B31","B32","B35"],"sheetName":"CashForecast"}'::jsonb,'{"cells":{"B10":-2100,"B11":2900,"B12":100,"B15":2900,"B20":-300,"B21":2600,"B22":400,"B25":2600,"B30":200,"B31":2800,"B32":200,"B35":400}}'::jsonb,'[{"id":"m1_net","kind":"cell_value","target":"B10","weight":1,"expected":-2100,"label_en":"Month 1 net cash movement = −2,100","label_ar":"صافي الحركة النقدية للشهر 1 = −2,100","tolerance":0.01},{"id":"m1_closing","kind":"cell_value","target":"B11","weight":1,"expected":2900,"label_en":"Month 1 closing cash = 2,900","label_ar":"الرصيد الختامي للشهر 1 = 2,900","tolerance":0.01},{"id":"m2_closing","kind":"cell_value","target":"B21","weight":2,"expected":2600,"label_en":"Month 2 closing cash = 2,600 (opening rolled from M1)","label_ar":"الرصيد الختامي للشهر 2 = 2,600 (الافتتاح مُرحّل من الشهر 1)","tolerance":0.01},{"id":"m3_closing","kind":"cell_value","target":"B31","weight":2,"expected":2800,"label_en":"Month 3 closing cash = 2,800","label_ar":"الرصيد الختامي للشهر 3 = 2,800","tolerance":0.01},{"id":"peak_shortfall","kind":"cell_value","target":"B35","weight":3,"expected":400,"label_en":"Peak funding shortfall vs 3,000 buffer = 400","label_ar":"ذروة عجز التمويل مقابل احتياطي 3,000 = 400","tolerance":0.01}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'Funding-Cost Sensitivity Data Table (Drawdown × Rate)','جدول حساسية تكلفة التمويل (السحب × سعر الفائدة)','','','AFP FP&A / ACT Treasury Risk Management; Basel III liquidity framework','advanced_spreadsheet',900,'VIFM Logistics is negotiating a committed revolving credit facility with Emirates NBD. Base case draws AED 50,000 (000s) at an all-in rate of 5.5%, so annual funding cost = drawn × rate. First compute the base annual funding cost in B5 (=B1*B3). Then build a NATIVE two-variable data table over the range C9:E11: column headers C8:E8 are the facility drawdown {40,000 / 50,000 / 60,000} feeding the drawdown input (B1), and row headers A9:A11 are the all-in rates {4.5% / 5.5% / 6.5%} feeding the rate input (B3). The corner cell B8 must link to the base funding-cost formula (=B5). Do not type the grid values - the table must be a genuine {=TABLE()} array so the cost surface recalculates if the base model changes.','تتفاوض شركة VIFM للخدمات اللوجستية على تسهيل ائتماني متجدد ملتزم به مع بنك الإمارات دبي الوطني. الحالة الأساسية تسحب 50,000 (بالآلاف) من الدراهم بسعر شامل 5.5%، أي أن تكلفة التمويل السنوية = المبلغ المسحوب × السعر. احسب أولًا تكلفة التمويل السنوية الأساسية في B5 (=B1*B3). ثم أنشئ جدول بيانات ثنائي المتغير أصلي على النطاق C9:E11: رؤوس الأعمدة C8:E8 هي مبالغ السحب {40,000 / 50,000 / 60,000} التي تُغذّي مدخل السحب (B1)، ورؤوس الصفوف A9:A11 هي الأسعار الشاملة {4.5% / 5.5% / 6.5%} التي تُغذّي مدخل السعر (B3). يجب أن ترتبط خلية الزاوية B8 بمعادلة التكلفة الأساسية (=B5). لا تكتب قيم الشبكة يدويًا - يجب أن يكون الجدول مصفوفة {=TABLE()} حقيقية حتى يُعاد احتساب سطح التكلفة عند تغيّر النموذج الأساسي.','{"rows":[{"A":"Facility drawdown (AED 000s)","B":50000,"r":1,"given":true},{"A":"(spacer)","r":2,"kind":"section"},{"A":"All-in interest rate","B":0.055,"r":3,"given":true},{"A":"(spacer)","r":4,"kind":"section"},{"A":"Base annual funding cost  =Drawdown×Rate","r":5,"ref":"B5","hint":"=B1*B3","editable":true},{"A":"Two-variable Data Table: rows=Rate, cols=Drawdown","r":7,"kind":"section"},{"A":"(corner formula links to base funding cost)","r":8,"ref":"B8","hint":"=B5","editable":true},{"C":40000,"D":50000,"E":60000,"r":8,"note":"drawdown headers C8:E8","given":true},{"A":0.045,"r":9,"note":"rate row header","given":true},{"A":0.055,"r":10,"given":true},{"A":0.065,"r":11,"given":true}],"model":{"drawdown":"B1","rate":"B3","fundingCost":"B5"},"currency":"AED 000s","editable":["B5","B8","C9:E11"],"dataTable":{"range":"C9:E11","corner":"B8","colInput":"B1","rowInput":"B3"},"sheetName":"FundingSensitivity"}'::jsonb,'{"cells":{"B5":2750,"B8":2750,"C9":1800,"D10":2750,"E11":3900}}'::jsonb,'[{"id":"array_formula","kind":"is_array_formula","target":"C9:E11","weight":3,"label_en":"Cost grid uses a native two-variable data table {=TABLE()} (not hardcoded)","label_ar":"تستخدم شبكة التكلفة جدول بيانات أصليًا ثنائي المتغير {=TABLE()} (وليس قيمًا ثابتة)"},{"id":"base_cost","kind":"cell_value","target":"B5","weight":1,"expected":2750,"label_en":"Base annual funding cost = 2,750 (50,000 × 5.5%)","label_ar":"تكلفة التمويل السنوية الأساسية = 2,750 (50,000 × 5.5%)","tolerance":0.01},{"id":"corner_low","kind":"cell_value","target":"C9","weight":1,"expected":1800,"label_en":"Low corner (40,000 @ 4.5%) = 1,800","label_ar":"الزاوية الدنيا (40,000 بسعر 4.5%) = 1,800","tolerance":0.01},{"id":"center","kind":"cell_value","target":"D10","weight":1,"expected":2750,"label_en":"Centre (50,000 @ 5.5%) = 2,750","label_ar":"المركز (50,000 بسعر 5.5%) = 2,750","tolerance":0.01},{"id":"corner_high","kind":"cell_value","target":"E11","weight":1,"expected":3900,"label_en":"High corner (60,000 @ 6.5%) = 3,900","label_ar":"الزاوية العليا (60,000 بسعر 6.5%) = 3,900","tolerance":0.01}]'::jsonb,2);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p2,'FX Hedge Valuation & Interest-Rate Shock Impact','تقييم تحوط الصرف الأجنبي وأثر صدمة سعر الفائدة','','','IFRS 9 Hedge Accounting / ACT FX & Interest-Rate Risk; CFA derivatives','logic_input',600,'VIFM Trading FZE has a USD 8,000,000 receivable due in 90 days and floating-rate debt of AED 200,000,000 priced at 3-month EIBOR + 150 bps. The current spot is AED/USD 3.6725 and the 90-day outright forward is 3.6680. Compute four figures that must reconcile to the underlying exposures: (1) the unhedged AED value of the receivable at spot; (2) the forward-hedged AED value at the 90-day outright forward; (3) the AED hedge cost (the give-up from locking the forward vs spot = unhedged spot value − forward-locked value); and (4) the annual incremental interest if 3-month EIBOR rises by 75 bps (principal × rate change; the 150 bps spread is unchanged so it does not enter the delta).','لدى شركة VIFM للتجارة (منطقة حرة) ذمم مدينة بقيمة 8,000,000 دولار أمريكي مستحقة خلال 90 يومًا، ودين بسعر فائدة متغير قدره 200,000,000 درهم مسعّر على أساس إيبور لثلاثة أشهر + 150 نقطة أساس. السعر الفوري الحالي هو 3.6725 درهم/دولار والسعر الآجل القاطع لـ 90 يومًا هو 3.6680. احسب أربعة أرقام يجب أن تتوافق مع التعرضات الأساسية: (1) القيمة بالدرهم غير المتحوط لها للذمم عند السعر الفوري؛ (2) القيمة بالدرهم المتحوط لها عند السعر الآجل القاطع لـ 90 يومًا؛ (3) تكلفة التحوط بالدرهم (الفرق الناتج عن تثبيت السعر الآجل مقابل الفوري = القيمة الفورية غير المتحوط لها − القيمة المثبتة آجلًا)؛ (4) الفائدة الإضافية السنوية إذا ارتفع إيبور لثلاثة أشهر بمقدار 75 نقطة أساس (أصل الدين × التغير في السعر؛ هامش الـ 150 نقطة أساس ثابت فلا يدخل في الفرق).','{"fields":[{"id":"unhedged_value","type":"number","label_en":"Unhedged AED value at spot","label_ar":"القيمة بالدرهم غير المتحوط لها عند السعر الفوري"},{"id":"forward_hedged_value","type":"number","label_en":"Forward-hedged AED value","label_ar":"القيمة بالدرهم المتحوط لها آجلًا"},{"id":"hedge_cost","type":"number","label_en":"Hedge cost (forward vs spot, AED)","label_ar":"تكلفة التحوط (آجل مقابل فوري، بالدرهم)"},{"id":"rate_shock_interest","type":"number","label_en":"Annual interest impact of +75 bps EIBOR (AED)","label_ar":"الأثر السنوي على الفائدة لارتفاع إيبور 75 نقطة أساس (بالدرهم)"}],"scenario":{"note_en":"Value the USD receivable unhedged at spot and hedged at the 90-day outright forward, derive the AED hedge cost, and quantify the annual interest sensitivity of the floating-rate debt to a +75 bps EIBOR shock. All four figures must reconcile.","note_ar":"قيّم الذمم بالدولار غير المتحوط لها عند السعر الفوري والمتحوط لها عند السعر الآجل القاطع لـ 90 يومًا، واستنتج تكلفة التحوط بالدرهم، وحدد حساسية الفائدة السنوية للدين متغير السعر تجاه صدمة إيبور +75 نقطة أساس. يجب أن تتوافق الأرقام الأربعة.","usd_receivable":8000000,"receivable_tenor_days":90,"spot_aed_usd":3.6725,"forward_90d_aed_usd":3.668,"floating_debt_aed":200000000,"debt_pricing":"3-month EIBOR + 150 bps","eibor_shock_bps":75,"spread_bps":150}}'::jsonb,'{"fields":{"unhedged_value":29380000,"forward_hedged_value":29344000,"hedge_cost":36000,"rate_shock_interest":1500000}}'::jsonb,'[{"id":"unhedged","kind":"logic_value","field":"unhedged_value","weight":1,"expected":29380000,"label_en":"Unhedged value at spot = 29,380,000 AED","label_ar":"القيمة غير المتحوط لها عند الفوري = 29,380,000 درهم","tolerance":1},{"id":"forward","kind":"logic_value","field":"forward_hedged_value","weight":2,"expected":29344000,"label_en":"Forward-hedged value = 29,344,000 AED","label_ar":"القيمة المتحوط لها آجلًا = 29,344,000 درهم","tolerance":1},{"id":"hedge_cost","kind":"logic_value","field":"hedge_cost","weight":3,"expected":36000,"label_en":"Hedge cost (forward vs spot) = 36,000 AED","label_ar":"تكلفة التحوط (آجل مقابل فوري) = 36,000 درهم","tolerance":1},{"id":"rate_shock","kind":"logic_value","field":"rate_shock_interest","weight":2,"expected":1500000,"label_en":"Annual interest impact of +75 bps EIBOR = 1,500,000 AED","label_ar":"الأثر السنوي على الفائدة لارتفاع إيبور 75 نقطة أساس = 1,500,000 درهم","tolerance":1}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p3,'Consolidated Cleared Cash Position by Bank','المركز النقدي المقاص الموحّد حسب البنك','','','ISO 20022 cash reporting (camt) / AFP CTP bank-relationship & liquidity reporting','sql',600,'VIFM Holding maintains accounts across four GCC banks. The bank_accounts ledger holds one row per balance line (bank, currency, balance_aed, status) where status is ''cleared'' or ''pending''. To produce the daily group cash position, report only CLEARED balances, totalled per bank, ranked from the largest cash holding to the smallest (pending items excluded) so concentration vs counterparty limits can be reviewed. Return exactly two columns: bank, total — ordered by total descending (break ties by bank).','تحتفظ شركة VIFM القابضة بحسابات لدى أربعة بنوك خليجية. يحتوي سجل bank_accounts على صف واحد لكل سطر رصيد (bank, currency, balance_aed, status) حيث تكون الحالة ''cleared'' أو ''pending''. لإنتاج المركز النقدي اليومي للمجموعة، أبلغ فقط عن الأرصدة المقاصة (cleared)، مجمّعة لكل بنك، ومرتبة من أكبر رصيد نقدي إلى أصغره (مع استبعاد البنود المعلّقة) حتى يمكن مراجعة التركّز مقابل حدود الأطراف المقابلة. أعد عمودين بالضبط: bank, total — مرتبة تنازليًا حسب total (وعند التساوي رتّب حسب bank).','{"dialect":"postgres","schema_sql":"CREATE TABLE bank_accounts (id int PRIMARY KEY, bank text, currency text, balance_aed numeric, status text);","seed_sql":"INSERT INTO bank_accounts (id, bank, currency, balance_aed, status) VALUES (1,''ENBD'',''AED'',4200,''cleared''),(2,''ENBD'',''AED'',1800,''cleared''),(3,''ENBD'',''AED'',900,''pending''),(4,''FAB'',''AED'',5400,''cleared''),(5,''ADCB'',''AED'',3500,''cleared''),(6,''ADCB'',''AED'',600,''pending''),(7,''Mashreq'',''AED'',2100,''cleared''),(8,''Mashreq'',''AED'',700,''cleared'');","prompt_en":"Return total cleared cash per bank, largest first. Columns: bank, total.","prompt_ar":"أعد إجمالي النقد المقاص لكل بنك، الأكبر أولًا. الأعمدة: bank, total."}'::jsonb,'{"master_query":"SELECT bank, SUM(balance_aed) AS total FROM bank_accounts WHERE status = ''cleared'' GROUP BY bank ORDER BY total DESC, bank"}'::jsonb,'[{"id":"result_match","kind":"sql_result_match","weight":3,"ordered":true,"label_en":"Per-bank cleared totals, largest first, pending excluded (ENBD 6000, FAB 5400, ADCB 3500, Mashreq 2800)","label_ar":"إجمالي الأرصدة المقاصة لكل بنك، الأكبر أولًا، مع استبعاد المعلّق (ENBD 6000، FAB 5400، ADCB 3500، Mashreq 2800)"}]'::jsonb,1);
  UPDATE technical_functions SET node_status='active' WHERE id = fn;
END $$;

-- 1.11 Corporate Tax (Direct & Indirect Compliance)
DO $$
DECLARE fn uuid; p1 uuid; p2 uuid; p3 uuid;
BEGIN
  SELECT id INTO fn FROM technical_functions WHERE node_id='1.11';
  IF fn IS NULL THEN RAISE NOTICE 'function 1.11 not found, skipping'; RETURN; END IF;
  DELETE FROM technical_pillars WHERE function_id = fn;  -- re-runnable (cascades to blocks)
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Direct Tax Computation & Provisioning','احتساب الضريبة المباشرة وتكوين المخصصات',1) RETURNING id INTO p1;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Indirect Tax & Cross-Border Flows','الضريبة غير المباشرة والتدفقات العابرة للحدود',2) RETURNING id INTO p2;
  INSERT INTO technical_pillars (function_id,name_en,name_ar,sort_order) VALUES (fn,'Transfer Pricing & Compliance Interrogation','تسعير المعاملات بين الأطراف ذات العلاقة واستجواب الامتثال',3) RETURNING id INTO p3;
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'UAE Corporate Tax Computation - Accounting Profit to Liability','احتساب ضريبة الشركات الإماراتية - من الربح المحاسبي إلى الالتزام الضريبي','','','UAE Federal Decree-Law No. 47 of 2022 (Corporate Tax)','spreadsheet',1000,'Gulf Crescent Trading LLC (Dubai mainland) reports accounting net profit before tax of AED 2,400,000 for the tax period ending 31 Dec 2024. Build the tax computation that reconciles accounting profit to taxable income via permanent and timing adjustments, applies the AED 375,000 0% threshold under Article 3, and computes the 9% Corporate Tax liability. Given items: non-deductible fines AED 60,000 (add back), 50% client-entertainment disallowance on AED 200,000 spend = AED 100,000 (add back), accounting depreciation AED 300,000 (add back), tax depreciation AED 360,000 (deduct), exempt dividend income from a UAE subsidiary AED 150,000 (deduct). Complete the linked computation cells: Total add-backs (B8), Total deductions (B12), Taxable income (B13), Income above the 0% band (B15), Corporate Tax @ 9% (B16), and Effective tax rate (B17).','تُسجّل شركة جلف كريسنت للتجارة ذ.م.م (دبي - البر الرئيسي) صافي ربح محاسبي قبل الضريبة قدره 2,400,000 درهم للفترة الضريبية المنتهية في 31 ديسمبر 2024. ابنِ احتساب الضريبة الذي يُسوّي الربح المحاسبي إلى الدخل الخاضع للضريبة عبر التعديلات الدائمة والمؤقتة، ثم طبّق شريحة الصفر بالمائة البالغة 375,000 درهم بموجب المادة 3، واحتسب التزام ضريبة الشركات بنسبة 9%. البنود المعطاة: غرامات غير قابلة للخصم 60,000 درهم (إضافة)، عدم خصم 50% من ضيافة العملاء على إنفاق 200,000 درهم = 100,000 درهم (إضافة)، استهلاك محاسبي 300,000 درهم (إضافة)، استهلاك ضريبي 360,000 درهم (خصم)، دخل أرباح موزعة معفى من شركة تابعة إماراتية 150,000 درهم (خصم). أكمل الخلايا المرتبطة: إجمالي الإضافات (B8)، إجمالي الخصومات (B12)، الدخل الخاضع للضريبة (B13)، الدخل فوق شريحة الصفر (B15)، ضريبة الشركات بنسبة 9% (B16)، ومعدل الضريبة الفعلي (B17).','{"rows":[{"A":"Gulf Crescent Trading LLC - UAE Corporate Tax Computation (AED), Period to 31 Dec 2024","r":1,"kind":"title"},{"A":"Accounting Profit","r":2,"kind":"section"},{"A":"Accounting Net Profit Before Tax","B":2400000,"r":3,"given":true},{"A":"Add: Permanent / Timing Differences","r":4,"kind":"section"},{"A":"  Non-deductible fines","B":60000,"r":5,"given":true},{"A":"  50% entertainment disallowance (50% of 200,000)","B":100000,"r":6,"given":true},{"A":"  Accounting depreciation (add back)","B":300000,"r":7,"given":true},{"A":"  Total add-backs","r":8,"ref":"B8","hint":"=SUM(B5:B7)","editable":true},{"A":"Less: Deductions","r":9,"kind":"section"},{"A":"  Tax depreciation","B":360000,"r":10,"given":true},{"A":"  Exempt dividend income (UAE subsidiary)","B":150000,"r":11,"given":true},{"A":"  Total deductions","r":12,"ref":"B12","hint":"=SUM(B10:B11)","editable":true},{"A":"Taxable Income (= NPBT + add-backs - deductions)","r":13,"ref":"B13","hint":"=B3+B8-B12","editable":true},{"A":"0% Band (Article 3 small-business threshold)","B":375000,"r":14,"given":true},{"A":"Income above the 0% band","r":15,"ref":"B15","hint":"=B13-B14","editable":true},{"A":"Corporate Tax @ 9% (on income above band)","r":16,"ref":"B16","hint":"=B15*0.09","editable":true},{"A":"Effective Tax Rate (= tax / taxable income)","r":17,"ref":"B17","hint":"=B16/B13","editable":true}],"currency":"AED","editable":["B8","B12","B13","B15","B16","B17"],"sheetName":"CT Computation"}'::jsonb,'{"cells":{"B8":460000,"B12":510000,"B13":2350000,"B15":1975000,"B16":177750,"B17":0.0756}}'::jsonb,'[{"id":"add_backs","kind":"cell_value","target":"B8","weight":1,"expected":460000,"label_en":"Total add-backs = AED 460,000","label_ar":"إجمالي الإضافات = 460,000 درهم","tolerance":0.01},{"id":"deductions","kind":"cell_value","target":"B12","weight":1,"expected":510000,"label_en":"Total deductions = AED 510,000","label_ar":"إجمالي الخصومات = 510,000 درهم","tolerance":0.01},{"id":"taxable_income","kind":"cell_value","target":"B13","weight":2,"expected":2350000,"label_en":"Taxable income = AED 2,350,000","label_ar":"الدخل الخاضع للضريبة = 2,350,000 درهم","tolerance":0.01},{"id":"above_band","kind":"cell_value","target":"B15","weight":2,"expected":1975000,"label_en":"Income above 0% band = AED 1,975,000","label_ar":"الدخل فوق شريحة الصفر = 1,975,000 درهم","tolerance":0.01},{"id":"ct_liability","kind":"cell_value","target":"B16","weight":3,"expected":177750,"label_en":"Corporate Tax @ 9% = AED 177,750","label_ar":"ضريبة الشركات بنسبة 9% = 177,750 درهم","tolerance":0.01},{"id":"etr","kind":"cell_value","target":"B17","weight":1,"expected":0.0756,"label_en":"Effective tax rate = 7.56%","label_ar":"معدل الضريبة الفعلي = 7.56%","tolerance":0.001}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p1,'Deferred Tax & Effective-Tax-Rate Reconciliation (IAS 12)','الضريبة المؤجلة وتسوية معدل الضريبة الفعلي (معيار المحاسبة الدولي 12)','','','IAS 12 Income Taxes','logic_input',600,'Sahara Logistics PJSC has a single asset with carrying amount AED 1,200,000 and tax base AED 900,000 at year-end (a taxable temporary difference). It also has an unused tax loss carried forward of AED 200,000 it expects to utilise. The UAE Corporate Tax rate is 9%. Current tax payable for the year is AED 90,000. Opening deferred tax was nil, so the period movement equals the closing balance. Compute, in the labelled numeric fields: the taxable temporary difference, the deferred tax liability, the deferred tax asset on the loss, the net deferred tax balance, and the total tax expense (current + movement in deferred).','تمتلك شركة الصحراء للخدمات اللوجستية ش.م.ع أصلًا واحدًا بقيمة دفترية 1,200,000 درهم وأساس ضريبي 900,000 درهم في نهاية السنة (فرق مؤقت خاضع للضريبة). كما لديها خسارة ضريبية مرحّلة غير مستخدمة قدرها 200,000 درهم تتوقع الاستفادة منها. معدل ضريبة الشركات الإماراتية 9%. الضريبة الحالية المستحقة للسنة 90,000 درهم. كان رصيد الضريبة المؤجلة الافتتاحي صفرًا، لذا فإن حركة الفترة تساوي الرصيد الختامي. احتسب في الحقول الرقمية: الفرق المؤقت الخاضع للضريبة، التزام الضريبة المؤجلة، أصل الضريبة المؤجلة على الخسارة، صافي رصيد الضريبة المؤجلة، وإجمالي مصروف الضريبة (الحالية + حركة الضريبة المؤجلة).','{"fields":[{"id":"temporary_difference","type":"number","label_en":"Taxable temporary difference (AED)","label_ar":"الفرق المؤقت الخاضع للضريبة (درهم)"},{"id":"deferred_tax_liability","type":"number","label_en":"Deferred tax liability (AED)","label_ar":"التزام الضريبة المؤجلة (درهم)"},{"id":"deferred_tax_asset","type":"number","label_en":"Deferred tax asset on loss (AED)","label_ar":"أصل الضريبة المؤجلة على الخسارة (درهم)"},{"id":"net_deferred_tax","type":"number","label_en":"Net deferred tax balance (AED)","label_ar":"صافي رصيد الضريبة المؤجلة (درهم)"},{"id":"total_tax_expense","type":"number","label_en":"Total tax expense (AED)","label_ar":"إجمالي مصروف الضريبة (درهم)"}],"scenario":{"note_en":"Deferred tax arises on the temporary difference between carrying amount and tax base, and on the recognised tax loss; multiply each by the 9% rate. Net the DTL against the DTA. Total tax expense = current tax + movement in net deferred tax (opening deferred was nil).","note_ar":"تنشأ الضريبة المؤجلة عن الفرق المؤقت بين القيمة الدفترية والأساس الضريبي، وعن الخسارة الضريبية المعترف بها؛ اضرب كلًا منهما في معدل 9%. قاص التزام الضريبة المؤجلة مع أصل الضريبة المؤجلة. إجمالي مصروف الضريبة = الضريبة الحالية + حركة صافي الضريبة المؤجلة (الرصيد الافتتاحي كان صفرًا).","carrying_amount":1200000,"tax_base":900000,"tax_loss_carried_forward":200000,"tax_rate":0.09,"current_tax_payable":90000,"opening_deferred_tax":0}}'::jsonb,'{"fields":{"temporary_difference":300000,"deferred_tax_liability":27000,"deferred_tax_asset":18000,"net_deferred_tax":9000,"total_tax_expense":99000}}'::jsonb,'[{"id":"temp_diff","kind":"logic_value","field":"temporary_difference","weight":1,"expected":300000,"label_en":"Taxable temporary difference = AED 300,000","label_ar":"الفرق المؤقت الخاضع للضريبة = 300,000 درهم","tolerance":0.5},{"id":"dtl","kind":"logic_value","field":"deferred_tax_liability","weight":2,"expected":27000,"label_en":"Deferred tax liability = AED 27,000","label_ar":"التزام الضريبة المؤجلة = 27,000 درهم","tolerance":0.5},{"id":"dta","kind":"logic_value","field":"deferred_tax_asset","weight":2,"expected":18000,"label_en":"Deferred tax asset on loss = AED 18,000","label_ar":"أصل الضريبة المؤجلة على الخسارة = 18,000 درهم","tolerance":0.5},{"id":"net_dt","kind":"logic_value","field":"net_deferred_tax","weight":2,"expected":9000,"label_en":"Net deferred tax = AED 9,000 liability","label_ar":"صافي الضريبة المؤجلة = 9,000 درهم التزام","tolerance":0.5},{"id":"total_tax","kind":"logic_value","field":"total_tax_expense","weight":3,"expected":99000,"label_en":"Total tax expense = AED 99,000","label_ar":"إجمالي مصروف الضريبة = 99,000 درهم","tolerance":0.5}]'::jsonb,2);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p2,'UAE VAT Return - Net Payable with Partial Exemption','إقرار ضريبة القيمة المضافة الإماراتية - صافي المستحق مع الإعفاء الجزئي','','','UAE Federal Decree-Law No. 8 of 2017 (VAT)','logic_input',600,'Marina Property Holdings (UAE, VAT-registered) files a quarterly VAT return at the 5% standard rate. Standard-rated sales (taxable supplies) were AED 4,000,000; exempt residential-lease supplies were AED 1,000,000. Total input VAT incurred was AED 90,000, of which AED 60,000 is directly attributable to taxable supplies (fully recoverable), AED 12,000 is directly attributable to exempt supplies (non-recoverable), and AED 18,000 is residual (overhead) input VAT apportioned by the standard turnover-based method. Compute, in the labelled numeric fields: output VAT, the recoverable share of residual input VAT, total recoverable input VAT, and net VAT payable to the FTA.','تقدّم شركة مارينا العقارية القابضة (الإمارات، مسجّلة لضريبة القيمة المضافة) إقرارًا ربع سنوي بنسبة 5% القياسية. كانت المبيعات الخاضعة للنسبة القياسية (التوريدات الخاضعة للضريبة) 4,000,000 درهم؛ والتوريدات المعفاة من تأجير المساكن 1,000,000 درهم. بلغ إجمالي ضريبة المدخلات المتكبّدة 90,000 درهم، منها 60,000 درهم منسوبة مباشرة للتوريدات الخاضعة (قابلة للاسترداد بالكامل)، و12,000 درهم منسوبة مباشرة للتوريدات المعفاة (غير قابلة للاسترداد)، و18,000 درهم متبقية (عامة) توزّع بطريقة دوران الأعمال القياسية. احتسب في الحقول الرقمية: ضريبة المخرجات، الحصة القابلة للاسترداد من ضريبة المدخلات المتبقية، إجمالي ضريبة المدخلات القابلة للاسترداد، وصافي ضريبة القيمة المضافة المستحقة للهيئة الاتحادية للضرائب.','{"fields":[{"id":"output_vat","type":"number","label_en":"Output VAT (AED)","label_ar":"ضريبة المخرجات (درهم)"},{"id":"recoverable_residual","type":"number","label_en":"Recoverable residual input VAT (AED)","label_ar":"ضريبة المدخلات المتبقية القابلة للاسترداد (درهم)"},{"id":"total_recoverable_input","type":"number","label_en":"Total recoverable input VAT (AED)","label_ar":"إجمالي ضريبة المدخلات القابلة للاسترداد (درهم)"},{"id":"net_vat_payable","type":"number","label_en":"Net VAT payable (AED)","label_ar":"صافي ضريبة القيمة المضافة المستحقة (درهم)"}],"scenario":{"note_en":"Output VAT is 5% on standard-rated supplies only (exempt supplies carry no output VAT). The recovery ratio = taxable turnover / total turnover. Residual input VAT is recoverable only at that ratio; input VAT directly attributable to exempt supplies is blocked. Net payable = output VAT - total recoverable input VAT.","note_ar":"ضريبة المخرجات هي 5% على التوريدات الخاضعة للنسبة القياسية فقط (التوريدات المعفاة لا تحمل ضريبة مخرجات). نسبة الاسترداد = دوران الأعمال الخاضع / إجمالي دوران الأعمال. ضريبة المدخلات المتبقية قابلة للاسترداد بتلك النسبة فقط؛ ضريبة المدخلات المنسوبة مباشرة للتوريدات المعفاة محظورة. صافي المستحق = ضريبة المخرجات - إجمالي ضريبة المدخلات القابلة للاسترداد.","standard_rate":0.05,"taxable_supplies":4000000,"exempt_supplies":1000000,"total_input_vat":90000,"input_vat_direct_taxable":60000,"input_vat_direct_exempt":12000,"input_vat_residual":18000}}'::jsonb,'{"fields":{"output_vat":200000,"recoverable_residual":14400,"total_recoverable_input":74400,"net_vat_payable":125600}}'::jsonb,'[{"id":"output_vat","kind":"logic_value","field":"output_vat","weight":2,"expected":200000,"label_en":"Output VAT = AED 200,000","label_ar":"ضريبة المخرجات = 200,000 درهم","tolerance":0.5},{"id":"recoverable_residual","kind":"logic_value","field":"recoverable_residual","weight":3,"expected":14400,"label_en":"Recoverable residual input VAT = AED 14,400","label_ar":"ضريبة المدخلات المتبقية القابلة للاسترداد = 14,400 درهم","tolerance":0.5},{"id":"total_recoverable","kind":"logic_value","field":"total_recoverable_input","weight":2,"expected":74400,"label_en":"Total recoverable input VAT = AED 74,400","label_ar":"إجمالي ضريبة المدخلات القابلة للاسترداد = 74,400 درهم","tolerance":0.5},{"id":"net_payable","kind":"logic_value","field":"net_vat_payable","weight":3,"expected":125600,"label_en":"Net VAT payable = AED 125,600","label_ar":"صافي ضريبة القيمة المضافة المستحقة = 125,600 درهم","tolerance":0.5}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p3,'Arm''s-Length Markup Sensitivity Matrix (OECD TNMM)','مصفوفة حساسية هامش السعر العادل (طريقة صافي هامش المعاملات OECD)','','','OECD Transfer Pricing Guidelines (TNMM) / UAE Transfer Pricing Regulations','advanced_spreadsheet',900,'Falcon Distribution FZE provides intra-group distribution services and is tested under the Transactional Net Margin Method (TNMM) on a cost-plus basis. Its operating cost base is AED 5,000,000 and the base benchmarked markup is 8%. The arm''s-length transfer price = cost base x (1 + markup). Compute the base transfer price in B5, then build a NATIVE two-variable data table in C9:E11 that flexes the transfer price across cost bases (rows: 4,000,000 / 5,000,000 / 6,000,000) and benchmarked markups (columns: 5% / 8% / 11% - the inter-quartile range). The corner cell B8 must link to the live transfer-price formula; rows feed the cost base and columns feed the markup. The body must be a real data table, not hardcoded numbers.','تقدّم شركة فالكون للتوزيع (منطقة حرة) خدمات توزيع داخل المجموعة وتُختبر بطريقة صافي هامش المعاملات (TNMM) على أساس التكلفة زائد هامش. قاعدة التكلفة التشغيلية 5,000,000 درهم والهامش المرجعي الأساسي 8%. السعر العادل = قاعدة التكلفة × (1 + الهامش). احتسب السعر الأساسي في B5، ثم ابنِ جدول بيانات أصلي ثنائي المتغير في C9:E11 يُغيّر السعر عبر قواعد التكلفة (الصفوف: 4,000,000 / 5,000,000 / 6,000,000) والهوامش المرجعية (الأعمدة: 5% / 8% / 11% - النطاق الربيعي). يجب أن ترتبط خلية الزاوية B8 بمعادلة السعر الحية؛ الصفوف تُغذّي قاعدة التكلفة والأعمدة تُغذّي الهامش. يجب أن يكون الجدول جدول بيانات حقيقيًا وليس قيمًا ثابتة.','{"rows":[{"A":"Cost base (AED)","B":5000000,"r":1,"given":true},{"A":"Benchmarked markup (decimal)","B":0.08,"r":2,"given":true},{"A":"Arm''s-length transfer price  =CostBase x (1+Markup)","r":5,"ref":"B5","hint":"=B1*(1+B2)","editable":true},{"A":"Two-variable Data Table: rows=Cost base, cols=Markup","r":7,"kind":"section"},{"A":"(corner formula links to transfer price)","r":8,"ref":"B8","hint":"=B5","editable":true},{"C":0.05,"D":0.08,"E":0.11,"r":8,"note":"markup column headers C8:E8","given":true},{"A":4000000,"r":9,"note":"cost-base row header","given":true},{"A":5000000,"r":10,"given":true},{"A":6000000,"r":11,"given":true}],"model":{"costBase":"B1","markup":"B2","transferPrice":"B5"},"currency":"AED","editable":["B5","B8","C9:E11"],"dataTable":{"range":"C9:E11","corner":"B8","colInput":"B2","rowInput":"B1"},"sheetName":"TP Sensitivity"}'::jsonb,'{"cells":{"B5":5400000,"B8":5400000,"C9":4200000,"D10":5400000,"E11":6660000}}'::jsonb,'[{"id":"base_price","kind":"cell_value","target":"B5","weight":2,"expected":5400000,"label_en":"Base transfer price = AED 5,400,000 (cost 5m x 1.08)","label_ar":"السعر الأساسي = 5,400,000 درهم (تكلفة 5 مليون × 1.08)","tolerance":0.01},{"id":"array_formula","kind":"is_array_formula","target":"C9:E11","weight":3,"label_en":"Uses a native two-variable data table {=TABLE()} (not hardcoded)","label_ar":"يستخدم جدول بيانات أصلي ثنائي المتغير وليس قيمًا ثابتة"},{"id":"low_corner","kind":"cell_value","target":"C9","weight":1,"expected":4200000,"label_en":"Low corner = AED 4,200,000 (cost 4m, markup 5%)","label_ar":"الزاوية الدنيا = 4,200,000 درهم (تكلفة 4 مليون، هامش 5%)","tolerance":0.01},{"id":"base_case","kind":"cell_value","target":"D10","weight":1,"expected":5400000,"label_en":"Base case = AED 5,400,000 (cost 5m, markup 8%)","label_ar":"الحالة الأساسية = 5,400,000 درهم (تكلفة 5 مليون، هامش 8%)","tolerance":0.01},{"id":"high_corner","kind":"cell_value","target":"E11","weight":1,"expected":6660000,"label_en":"High corner = AED 6,660,000 (cost 6m, markup 11%)","label_ar":"الزاوية العليا = 6,660,000 درهم (تكلفة 6 مليون، هامش 11%)","tolerance":0.01}]'::jsonb,1);
  INSERT INTO technical_skill_blocks (pillar_id,name_en,name_ar,description_en,description_ar,framework_ref,engine_type,time_limit_seconds,prompt_en,prompt_ar,engine_config,master_solution,checkpoints,sort_order) VALUES (p3,'Intercompany Ledger Interrogation - TP Documentation Thresholds (SQL)','استجواب دفتر المعاملات بين الشركات - حدود توثيق تسعير المعاملات (SQL)','','','UAE Transfer Pricing Regulations / OECD Master File-Local File Thresholds','sql',600,'A seeded related_party_transactions ledger records intercompany dealings of a UAE group: id, counterparty, country, category (goods/services/royalty/loan_interest), amount_aed, is_related_party (boolean). Tax wants the aggregate related-party exposure per category to assess which categories breach the Local File documentation materiality threshold of AED 4,000,000. Write ONE query returning the category and the total related-party amount (column alias: total), for related-party transactions only, where the category total is at least AED 4,000,000, highest total first (then category as a tie-break). Columns: category, total.','يسجّل دفتر related_party_transactions المعاملات بين شركات مجموعة إماراتية: id، counterparty، country، category (goods/services/royalty/loan_interest)، amount_aed، is_related_party (قيمة منطقية). تريد الضريبة إجمالي التعرض للأطراف ذات العلاقة لكل فئة لتقييم الفئات التي تتجاوز حد المادية لتوثيق الملف المحلي البالغ 4,000,000 درهم. اكتب استعلامًا واحدًا يُرجع الفئة وإجمالي مبلغ الأطراف ذات العلاقة (الاسم المستعار: total)، لمعاملات الأطراف ذات العلاقة فقط، حيث يكون إجمالي الفئة 4,000,000 درهم على الأقل، من الأعلى إلى الأدنى (ثم الفئة لكسر التعادل). الأعمدة: category، total.','{"dialect":"postgres","schema_sql":"CREATE TABLE related_party_transactions (id int PRIMARY KEY, counterparty text, country text, category text, amount_aed numeric, is_related_party boolean);","seed_sql":"INSERT INTO related_party_transactions (id, counterparty, country, category, amount_aed, is_related_party) VALUES (1,''Falcon Trading FZE'',''UAE'',''goods'',2500000,true),(2,''Falcon Trading FZE'',''UAE'',''goods'',1800000,true),(3,''Desert IP Holding'',''Luxembourg'',''royalty'',4000000,true),(4,''Gulf Shared Services'',''KSA'',''services'',1500000,true),(5,''Gulf Shared Services'',''KSA'',''services'',1000000,true),(6,''Crescent Finance Ltd'',''Cayman'',''loan_interest'',900000,true),(7,''Open Market Supplier'',''UAE'',''goods'',5000000,false),(8,''External Consultant'',''Egypt'',''services'',700000,false);","prompt_en":"Return category and total related-party amount (alias total), for related-party transactions only, where the category total is at least AED 4,000,000, highest total first then category.","prompt_ar":"أرجع الفئة وإجمالي مبلغ الأطراف ذات العلاقة (الاسم المستعار total)، لمعاملات الأطراف ذات العلاقة فقط، حيث يكون إجمالي الفئة 4,000,000 درهم على الأقل، من الأعلى ثم الفئة."}'::jsonb,'{"master_query":"SELECT category, SUM(amount_aed) AS total FROM related_party_transactions WHERE is_related_party = true GROUP BY category HAVING SUM(amount_aed) >= 4000000 ORDER BY total DESC, category"}'::jsonb,'[{"id":"result_match","kind":"sql_result_match","weight":3,"ordered":true,"label_en":"Result matches master (related-party category totals >= AED 4m, correct order)","label_ar":"النتيجة تطابق النموذج (إجمالي فئات الأطراف ذات العلاقة >= 4 مليون درهم، بالترتيب الصحيح)"}]'::jsonb,2);
  UPDATE technical_functions SET node_status='active' WHERE id = fn;
END $$;
